#[allow(dead_code)]
fn sanitize_prebuilt_marketplace_name(name: &str) -> String {
    let sanitized = name
        .chars()
        .map(|ch| {
            if ch.is_ascii_alphanumeric() || ch == '-' {
                ch
            } else {
                '-'
            }
        })
        .collect::<String>();
    let sanitized = sanitized.trim_matches('-').to_string();
    if sanitized.is_empty() {
        "prebuilt-agent".to_string()
    } else {
        sanitized
    }
}

