// ── Conductor Build ─────────────────────────────────────────────────

pub fn conduct_build(
    state: &AppState,
    prompt: String,
    output_dir: Option<String>,
    model: Option<String>,
) -> Result<serde_json::Value, String> {
    let home = std::env::var("HOME").unwrap_or_else(|_| ".".to_string());
    let timestamp = std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .unwrap_or_default()
        .as_secs();
    let out_dir = output_dir.unwrap_or_else(|| format!("{home}/.nexus/builds/{timestamp}"));

    // Ensure output directory exists
    std::fs::create_dir_all(&out_dir).map_err(|e| format!("failed to create output dir: {e}"))?;

    let full_model = model.unwrap_or_else(|| "mistral".to_string());

    // Route to the correct provider based on prefix (e.g. "anthropic/claude-sonnet-4-20250514")
    let config = load_config().map_err(agent_error)?;
    let prov_config = build_provider_config(&config);
    let (provider, model_name) = provider_from_prefixed_model(&full_model, &prov_config)?;

    // Create conductor
    let mut conductor = Conductor::new(provider, &model_name);

    // Create user request
    let request = UserRequest::new(&prompt, &out_dir);
    let request_id = request.id;

    // Get supervisor
    let mut supervisor = state.supervisor.lock().unwrap_or_else(|p| p.into_inner());

    // Preview plan first (for event emission by caller)
    let plan = conductor
        .preview_plan(&UserRequest::new(&prompt, &out_dir))
        .map_err(|e| format!("planning failed: {e}"))?;
    let plan_json = serde_json::to_value(&plan).unwrap_or_default();

    // Run full orchestration
    let start = std::time::Instant::now();
    let mut result = conductor
        .run(request, &mut supervisor)
        .map_err(|e| format!("conductor failed: {e}"))?;
    result.duration_secs = start.elapsed().as_secs_f64();

    drop(supervisor);

    // Log audit event
    state.log_event(
        Uuid::nil(),
        EventType::StateChange,
        json!({
            "source": "conductor",
            "action": "conduct_build",
            "request_id": request_id.to_string(),
            "status": format!("{:?}", result.status),
            "agents_used": result.agents_used,
            "total_fuel_used": result.total_fuel_used,
            "duration_secs": result.duration_secs,
        }),
    );

    let result_json = serde_json::to_value(&result).unwrap_or_default();
    Ok(json!({
        "plan": plan_json,
        "result": result_json,
    }))
}

// ── Typed Tools ─────────────────────────────────────────────────────

pub fn execute_tool(state: &AppState, tool_json: String) -> Result<String, String> {
    use nexus_kernel::typed_tools::{self, TypedTool};

    let tool: TypedTool =
        serde_json::from_str(&tool_json).map_err(|e| format!("invalid tool JSON: {e}"))?;

    // Validate arguments first
    tool.validate()?;

    // Check fuel cost
    let cost = tool.fuel_cost();

    // If destructive or custom-with-approval, flag for HITL
    let needs_hitl = tool.is_destructive()
        || matches!(
            &tool,
            TypedTool::Custom {
                requires_approval: true,
                ..
            }
        );

    // Execute
    let cwd = std::env::current_dir().unwrap_or_else(|_| std::path::PathBuf::from("."));
    let output = typed_tools::execute_typed_tool(&tool, &cwd)?;

    // Audit log
    state.log_event(
        uuid::Uuid::nil(),
        EventType::StateChange,
        json!({
            "source": "typed-tools",
            "tool": output.tool,
            "exit_code": output.exit_code,
            "duration_ms": output.duration_ms,
            "fuel_cost": cost,
            "capability": tool.capability_required(),
            "destructive": tool.is_destructive(),
            "hitl_required": needs_hitl,
        }),
    );

    serde_json::to_string(&output).map_err(|e| e.to_string())
}

pub fn list_tools() -> Result<String, String> {
    let tools = nexus_kernel::typed_tools::list_available_tools();
    serde_json::to_string(&tools).map_err(|e| e.to_string())
}

/// Parse a shell command string into a TypedTool and execute it.
///
/// Maps well-known commands to safe TypedTool variants.  Unknown commands
/// become `TypedTool::Custom` with `requires_approval: true`.
///
/// Returns JSON-serialised `TerminalResult`.
pub fn terminal_execute(state: &AppState, command: String, cwd: String) -> Result<String, String> {
    state.check_rate(nexus_kernel::rate_limit::RateCategory::AgentExecute)?;
    state.validate_input(&command)?;
    state.validate_path_input(&cwd)?;
    use nexus_kernel::typed_tools::{self, TypedTool};

    #[derive(serde::Serialize)]
    struct TerminalResult {
        stdout: String,
        stderr: String,
        exit_code: i32,
        duration_ms: u64,
        tool: String,
        needs_approval: bool,
        fuel_cost: u64,
    }

    let parts: Vec<&str> = command.split_whitespace().collect();
    if parts.is_empty() {
        return Err("empty command".into());
    }

    let working_dir = std::path::PathBuf::from(&cwd);
    if !working_dir.is_dir() {
        return Err(format!("directory does not exist: {cwd}"));
    }

    // Parse command string → TypedTool
    let tool: TypedTool = match parts[0] {
        "git" => match parts.get(1).copied() {
            Some("status") => TypedTool::GitStatus,
            Some("diff") => {
                let path = parts.get(2).map(|s| s.to_string());
                TypedTool::GitDiff { path }
            }
            Some("log") => {
                let count = parts
                    .iter()
                    .find_map(|p| p.strip_prefix('-').and_then(|n| n.parse::<usize>().ok()))
                    .unwrap_or(10);
                TypedTool::GitLog { count }
            }
            Some("commit") => {
                let msg = if let Some(pos) = parts.iter().position(|p| *p == "-m") {
                    parts[pos + 1..]
                        .join(" ")
                        .trim_matches('"')
                        .trim_matches('\'')
                        .to_string()
                } else {
                    String::new()
                };
                TypedTool::GitCommit { message: msg }
            }
            Some("push") => {
                let remote = parts.get(2).unwrap_or(&"origin").to_string();
                let branch = parts.get(3).unwrap_or(&"main").to_string();
                TypedTool::GitPush { remote, branch }
            }
            Some("pull") => {
                let remote = parts.get(2).unwrap_or(&"origin").to_string();
                let branch = parts.get(3).unwrap_or(&"main").to_string();
                TypedTool::GitPull { remote, branch }
            }
            Some("checkout") => {
                let branch = parts.get(2).unwrap_or(&"main").to_string();
                TypedTool::GitCheckout { branch }
            }
            _ => TypedTool::Custom {
                program: "git".into(),
                args: parts[1..].iter().map(|s| s.to_string()).collect(),
                requires_approval: false,
            },
        },
        "cargo" => match parts.get(1).copied() {
            Some("build") | Some("b") => {
                let release = parts.contains(&"--release");
                let package = parts
                    .iter()
                    .position(|p| *p == "-p" || *p == "--package")
                    .and_then(|i| parts.get(i + 1))
                    .map(|s| s.to_string());
                TypedTool::CargoBuild { package, release }
            }
            Some("test") | Some("t") => {
                let package = parts
                    .iter()
                    .position(|p| *p == "-p" || *p == "--package")
                    .and_then(|i| parts.get(i + 1))
                    .map(|s| s.to_string());
                let test_name = parts.get(2).and_then(|s| {
                    if s.starts_with('-') {
                        None
                    } else {
                        Some(s.to_string())
                    }
                });
                TypedTool::CargoTest { package, test_name }
            }
            Some("fmt") => {
                let check = parts.contains(&"--check");
                TypedTool::CargoFmt { check }
            }
            Some("clippy") => {
                let deny_warnings = parts.contains(&"-D") || parts.contains(&"warnings");
                TypedTool::CargoClippy { deny_warnings }
            }
            Some("run") | Some("r") => {
                let package = parts
                    .iter()
                    .position(|p| *p == "-p" || *p == "--package")
                    .and_then(|i| parts.get(i + 1))
                    .map(|s| s.to_string());
                let extra_args: Vec<String> =
                    if let Some(pos) = parts.iter().position(|p| *p == "--") {
                        parts[pos + 1..].iter().map(|s| s.to_string()).collect()
                    } else {
                        vec![]
                    };
                TypedTool::CargoRun {
                    package,
                    args: extra_args,
                }
            }
            _ => TypedTool::Custom {
                program: "cargo".into(),
                args: parts[1..].iter().map(|s| s.to_string()).collect(),
                requires_approval: false,
            },
        },
        "npm" => match (parts.get(1).copied(), parts.get(2).copied()) {
            (Some("install") | Some("ci") | Some("i"), _) => TypedTool::NpmInstall,
            (Some("test"), _) => TypedTool::NpmTest,
            (Some("run"), Some("build")) => TypedTool::NpmBuild,
            (Some("run"), Some(script)) => TypedTool::NpmRun {
                script: script.to_string(),
            },
            _ => TypedTool::Custom {
                program: "npm".into(),
                args: parts[1..].iter().map(|s| s.to_string()).collect(),
                requires_approval: false,
            },
        },
        "ls" => {
            let recursive = parts.iter().any(|p| p.contains('R'));
            let path = parts
                .iter()
                .find(|p| !p.starts_with('-') && **p != "ls")
                .map(|s| s.to_string())
                .unwrap_or_else(|| ".".into());
            TypedTool::FileList { path, recursive }
        }
        "dir" => TypedTool::FileList {
            path: ".".into(),
            recursive: false,
        },
        "pwd" => TypedTool::Custom {
            program: "pwd".into(),
            args: vec![],
            requires_approval: false,
        },
        "cat" | "head" | "tail" => TypedTool::Custom {
            program: parts[0].to_string(),
            args: parts[1..].iter().map(|s| s.to_string()).collect(),
            requires_approval: false,
        },
        "echo" => TypedTool::Custom {
            program: "echo".into(),
            args: parts[1..].iter().map(|s| s.to_string()).collect(),
            requires_approval: false,
        },
        "whoami" | "date" | "uname" | "uptime" | "hostname" => TypedTool::Custom {
            program: parts[0].to_string(),
            args: parts[1..].iter().map(|s| s.to_string()).collect(),
            requires_approval: false,
        },
        "ps" => TypedTool::ProcessList,
        "df" => TypedTool::DiskUsage {
            path: parts.get(1).unwrap_or(&".").to_string(),
        },
        "free" => TypedTool::Custom {
            program: "free".into(),
            args: parts[1..].iter().map(|s| s.to_string()).collect(),
            requires_approval: false,
        },
        "mkdir" => {
            let path = parts
                .iter()
                .find(|p| !p.starts_with('-') && **p != "mkdir")
                .map(|s| s.to_string())
                .unwrap_or_default();
            if path.is_empty() {
                return Err("mkdir: missing operand".into());
            }
            TypedTool::MakeDirectory { path }
        }
        "cp" => {
            if parts.len() < 3 {
                return Err("cp: missing operand".into());
            }
            TypedTool::FileCopy {
                from: parts[parts.len() - 2].to_string(),
                to: parts[parts.len() - 1].to_string(),
            }
        }
        "mv" => {
            if parts.len() < 3 {
                return Err("mv: missing operand".into());
            }
            TypedTool::FileMove {
                from: parts[1].to_string(),
                to: parts[2].to_string(),
            }
        }
        "rm" => {
            let path = parts
                .iter()
                .find(|p| !p.starts_with('-') && **p != "rm")
                .map(|s| s.to_string())
                .unwrap_or_default();
            if path.is_empty() {
                return Err("rm: missing operand".into());
            }
            TypedTool::FileRemove { path }
        }
        "python3" | "python" => {
            let script = parts.get(1).unwrap_or(&"--version").to_string();
            let args: Vec<String> = parts[2..].iter().map(|s| s.to_string()).collect();
            TypedTool::PythonRun { script, args }
        }
        "pip3" | "pip" => {
            if parts.get(1).copied() == Some("install") {
                TypedTool::PipInstall {
                    packages: parts[2..].iter().map(|s| s.to_string()).collect(),
                }
            } else {
                TypedTool::Custom {
                    program: parts[0].to_string(),
                    args: parts[1..].iter().map(|s| s.to_string()).collect(),
                    requires_approval: true,
                }
            }
        }
        "grep" | "rg" | "find" | "wc" | "sort" | "uniq" | "tree" | "which" | "env" | "printenv"
        | "touch" => TypedTool::Custom {
            program: parts[0].to_string(),
            args: parts[1..].iter().map(|s| s.to_string()).collect(),
            requires_approval: false,
        },
        _ => TypedTool::Custom {
            program: parts[0].to_string(),
            args: parts[1..].iter().map(|s| s.to_string()).collect(),
            requires_approval: true,
        },
    };

    let needs_approval = tool.is_destructive()
        || matches!(
            &tool,
            TypedTool::Custom {
                requires_approval: true,
                ..
            }
        );

    // If it needs approval, return early — frontend handles HITL confirmation
    if needs_approval {
        let result = TerminalResult {
            stdout: String::new(),
            stderr: String::new(),
            exit_code: -1,
            duration_ms: 0,
            tool: tool.tool_name(),
            needs_approval: true,
            fuel_cost: tool.fuel_cost(),
        };
        return serde_json::to_string(&result).map_err(|e| e.to_string());
    }

    // Execute
    let output = typed_tools::execute_typed_tool(&tool, &working_dir)?;
    let fuel_cost = tool.fuel_cost();

    // Audit log
    state.log_event(
        uuid::Uuid::nil(),
        EventType::StateChange,
        json!({
            "source": "terminal",
            "command": command,
            "tool": output.tool,
            "exit_code": output.exit_code,
            "duration_ms": output.duration_ms,
            "fuel_cost": fuel_cost,
        }),
    );

    let result = TerminalResult {
        stdout: output.stdout,
        stderr: output.stderr,
        exit_code: output.exit_code,
        duration_ms: output.duration_ms,
        tool: output.tool,
        needs_approval: false,
        fuel_cost,
    };
    serde_json::to_string(&result).map_err(|e| e.to_string())
}

/// Force-execute a command that previously required HITL approval.
/// Called after the user clicks "Approve" in the terminal UI.
pub fn terminal_execute_approved(
    state: &AppState,
    command: String,
    cwd: String,
) -> Result<String, String> {
    state.check_rate(nexus_kernel::rate_limit::RateCategory::AgentExecute)?;
    state.validate_input(&command)?;
    state.validate_path_input(&cwd)?;
    use nexus_kernel::typed_tools::{self, TypedTool};

    #[derive(serde::Serialize)]
    struct TerminalResult {
        stdout: String,
        stderr: String,
        exit_code: i32,
        duration_ms: u64,
        tool: String,
        needs_approval: bool,
        fuel_cost: u64,
    }

    let parts: Vec<&str> = command.split_whitespace().collect();
    if parts.is_empty() {
        return Err("empty command".into());
    }

    let working_dir = std::path::PathBuf::from(&cwd);

    // For approved commands, build the tool the same way but force-execute
    let tool = TypedTool::Custom {
        program: parts[0].to_string(),
        args: parts[1..].iter().map(|s| s.to_string()).collect(),
        requires_approval: false, // Already approved by HITL
    };

    let output = typed_tools::execute_typed_tool(&tool, &working_dir)?;
    let fuel_cost = tool.fuel_cost();

    state.log_event(
        uuid::Uuid::nil(),
        EventType::StateChange,
        json!({
            "source": "terminal-hitl-approved",
            "command": command,
            "tool": output.tool,
            "exit_code": output.exit_code,
            "duration_ms": output.duration_ms,
            "fuel_cost": fuel_cost,
        }),
    );

    let result = TerminalResult {
        stdout: output.stdout,
        stderr: output.stderr,
        exit_code: output.exit_code,
        duration_ms: output.duration_ms,
        tool: output.tool,
        needs_approval: false,
        fuel_cost,
    };
    serde_json::to_string(&result).map_err(|e| e.to_string())
}

// ── Replay Evidence ─────────────────────────────────────────────────

pub fn replay_list_bundles(
    state: &AppState,
    agent_id: Option<String>,
    limit: Option<usize>,
) -> Result<String, String> {
    let recorder = state
        .replay_recorder
        .lock()
        .unwrap_or_else(|p| p.into_inner());
    let bundles = recorder.list_bundles(agent_id.as_deref(), limit.unwrap_or(50));
    serde_json::to_string(&bundles).map_err(|e| e.to_string())
}

pub fn replay_get_bundle(state: &AppState, bundle_id: String) -> Result<String, String> {
    let recorder = state
        .replay_recorder
        .lock()
        .unwrap_or_else(|p| p.into_inner());
    let bundle = recorder
        .get_bundle(&bundle_id)
        .ok_or_else(|| format!("bundle '{bundle_id}' not found"))?;
    serde_json::to_string(bundle).map_err(|e| e.to_string())
}

pub fn replay_verify_bundle(state: &AppState, bundle_id: String) -> Result<String, String> {
    use nexus_kernel::replay::player::ReplayPlayer;

    let recorder = state
        .replay_recorder
        .lock()
        .unwrap_or_else(|p| p.into_inner());
    let bundle = recorder
        .get_bundle(&bundle_id)
        .ok_or_else(|| format!("bundle '{bundle_id}' not found"))?;
    let verdict = ReplayPlayer::verify_bundle(bundle);

    drop(recorder);
    state.log_event(
        uuid::Uuid::nil(),
        EventType::StateChange,
        json!({
            "source": "replay-evidence",
            "action": "verify_bundle",
            "bundle_id": bundle_id,
            "verdict": serde_json::to_value(&verdict).unwrap_or_default(),
        }),
    );

    serde_json::to_string(&verdict).map_err(|e| e.to_string())
}

pub fn replay_export_bundle(state: &AppState, bundle_id: String) -> Result<String, String> {
    let recorder = state
        .replay_recorder
        .lock()
        .unwrap_or_else(|p| p.into_inner());
    recorder.export_bundle(&bundle_id)
}

pub fn replay_toggle_recording(state: &AppState, enabled: bool) -> Result<String, String> {
    let mut recorder = state
        .replay_recorder
        .lock()
        .unwrap_or_else(|p| p.into_inner());
    if enabled {
        recorder.start_recording();
    } else {
        recorder.stop_recording();
    }

    drop(recorder);
    state.log_event(
        uuid::Uuid::nil(),
        EventType::StateChange,
        json!({
            "source": "replay-evidence",
            "action": "toggle_recording",
            "enabled": enabled,
        }),
    );

    serde_json::to_string(&serde_json::json!({"recording": enabled})).map_err(|e| e.to_string())
}

// ── Air-Gap Deployment ──────────────────────────────────────────────

pub fn airgap_create_bundle(
    _state: &AppState,
    target_os: String,
    target_arch: String,
    output_path: String,
    components: Option<String>,
) -> Result<String, String> {
    let mut builder = nexus_airgap::AirgapBuilder::new(&target_os, &target_arch);

    // If components JSON array provided, add each
    if let Some(comp_json) = components {
        let comps: Vec<nexus_airgap::BundleComponent> =
            serde_json::from_str(&comp_json).map_err(|e| format!("invalid components: {e}"))?;
        for comp in comps {
            builder.add_component(comp);
        }
    }

    let bundle = builder.build(&output_path)?;
    serde_json::to_string(&bundle).map_err(|e| e.to_string())
}

pub fn airgap_validate_bundle(_state: &AppState, bundle_path: String) -> Result<String, String> {
    let result = nexus_airgap::AirgapInstaller::validate_bundle(&bundle_path);
    serde_json::to_string(&result).map_err(|e| e.to_string())
}

pub fn airgap_install_bundle(
    state: &AppState,
    bundle_path: String,
    install_dir: String,
) -> Result<String, String> {
    let bundle = nexus_airgap::AirgapInstaller::install(&bundle_path, &install_dir)?;

    state.log_event(
        uuid::Uuid::nil(),
        EventType::StateChange,
        json!({
            "source": "airgap",
            "action": "install_bundle",
            "bundle_id": bundle.id,
            "install_dir": install_dir,
        }),
    );

    serde_json::to_string(&bundle).map_err(|e| e.to_string())
}

pub fn airgap_get_system_info(_state: &AppState) -> Result<String, String> {
    let info = nexus_airgap::get_system_info();
    serde_json::to_string(&info).map_err(|e| e.to_string())
}

// ── Reputation Registry ─────────────────────────────────────────────

pub fn reputation_register(state: &AppState, did: String, name: String) -> Result<String, String> {
    let mut reg = state
        .reputation_registry
        .lock()
        .unwrap_or_else(|p| p.into_inner());
    let rep = reg.register_agent(&did, &name);

    drop(reg);
    state.log_event(
        uuid::Uuid::nil(),
        EventType::StateChange,
        json!({
            "source": "reputation",
            "action": "register",
            "agent_did": did,
        }),
    );

    serde_json::to_string(&rep).map_err(|e| e.to_string())
}

pub fn reputation_record_task(
    state: &AppState,
    did: String,
    success: bool,
) -> Result<String, String> {
    let mut reg = state
        .reputation_registry
        .lock()
        .unwrap_or_else(|p| p.into_inner());
    reg.record_task_completion(&did, success);
    reg.award_badges(&did);
    let rep = reg
        .get_reputation(&did)
        .ok_or_else(|| format!("agent '{did}' not found"))?;
    serde_json::to_string(rep).map_err(|e| e.to_string())
}

pub fn reputation_rate_agent(
    state: &AppState,
    did: String,
    rater_did: String,
    score: f64,
    comment: Option<String>,
) -> Result<String, String> {
    let mut reg = state
        .reputation_registry
        .lock()
        .unwrap_or_else(|p| p.into_inner());
    reg.add_peer_rating(&did, &rater_did, score, comment);
    reg.award_badges(&did);
    let rep = reg
        .get_reputation(&did)
        .ok_or_else(|| format!("agent '{did}' not found"))?;
    serde_json::to_string(rep).map_err(|e| e.to_string())
}

pub fn reputation_get(state: &AppState, did: String) -> Result<String, String> {
    let reg = state
        .reputation_registry
        .lock()
        .unwrap_or_else(|p| p.into_inner());
    let rep = reg
        .get_reputation(&did)
        .ok_or_else(|| format!("agent '{did}' not found"))?;
    serde_json::to_string(rep).map_err(|e| e.to_string())
}

pub fn reputation_top(state: &AppState, limit: Option<usize>) -> Result<String, String> {
    let reg = state
        .reputation_registry
        .lock()
        .unwrap_or_else(|p| p.into_inner());
    let top = reg.top_agents(limit.unwrap_or(10));
    serde_json::to_string(&top).map_err(|e| e.to_string())
}

pub fn reputation_export(state: &AppState, did: String) -> Result<String, String> {
    let reg = state
        .reputation_registry
        .lock()
        .unwrap_or_else(|p| p.into_inner());
    reg.export_reputation(&did)
}

pub fn reputation_import(state: &AppState, json: String) -> Result<String, String> {
    let mut reg = state
        .reputation_registry
        .lock()
        .unwrap_or_else(|p| p.into_inner());
    let rep = reg.import_reputation(&json)?;

    drop(reg);
    state.log_event(
        uuid::Uuid::nil(),
        EventType::StateChange,
        json!({
            "source": "reputation",
            "action": "import",
            "agent_did": rep.agent_did,
        }),
    );

    serde_json::to_string(&rep).map_err(|e| e.to_string())
}

// ── Trust Overview ──────────────────────────────────────────────────

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct TrustOverviewAgent {
    pub id: String,
    pub name: String,
    pub did: Option<String>,
    pub autonomy_level: u8,
    pub trust_score: f64,
    pub total_tasks: u64,
    pub success_rate: f64,
    pub violations: u64,
    pub fuel_remaining: u64,
    pub fuel_budget: u64,
    pub status: String,
    pub badges: Vec<String>,
    pub last_updated: u64,
}

pub fn get_trust_overview(state: &AppState) -> Result<Vec<TrustOverviewAgent>, String> {
    let supervisor = state.supervisor.lock().unwrap_or_else(|p| p.into_inner());
    let meta_guard = state.meta.lock().unwrap_or_else(|p| p.into_inner());
    let id_mgr = state.identity_mgr.lock().unwrap_or_else(|p| p.into_inner());
    let mut rep_reg = state
        .reputation_registry
        .lock()
        .unwrap_or_else(|p| p.into_inner());

    let statuses = supervisor.health_check();
    let mut result = Vec::new();

    for status in &statuses {
        let meta = meta_guard.get(&status.id).cloned().unwrap_or(AgentMeta {
            name: "unknown".to_string(),
            last_action: "none".to_string(),
        });

        let handle = supervisor.get_agent(status.id);
        let autonomy_level = handle.map(|h| h.autonomy_level).unwrap_or(0);
        let fuel_budget = handle.map(|h| h.manifest.fuel_budget).unwrap_or(0);

        // Get or create DID
        let did = id_mgr.get(&status.id).map(|id| id.did.clone());
        let did_str = did
            .clone()
            .unwrap_or_else(|| format!("did:nexus:{}", status.id));

        // Auto-register in reputation if not already present
        if rep_reg.get_reputation(&did_str).is_none() {
            rep_reg.register_agent(&did_str, &meta.name);
        }

        let (trust_score, total_tasks, success_rate, violations, badges, last_updated) =
            match rep_reg.get_reputation(&did_str) {
                Some(rep) => (
                    rep.reputation_score,
                    rep.total_tasks_completed + rep.total_tasks_failed,
                    rep.success_rate,
                    rep.governance_violations,
                    rep.badges.iter().map(|b| format!("{b:?}")).collect(),
                    rep.last_updated,
                ),
                None => (0.5, 0, 0.0, 0, Vec::new(), 0),
            };

        result.push(TrustOverviewAgent {
            id: status.id.to_string(),
            name: meta.name,
            did,
            autonomy_level,
            trust_score,
            total_tasks,
            success_rate,
            violations,
            fuel_remaining: status.remaining_fuel,
            fuel_budget,
            status: status.state.to_string(),
            badges,
            last_updated,
        });
    }

    result.sort_by(|a, b| {
        b.trust_score
            .partial_cmp(&a.trust_score)
            .unwrap_or(std::cmp::Ordering::Equal)
    });
    Ok(result)
}

// ── Computer Control Engine ──────────────────────────────────────────

fn desktop_control_workspace() -> PathBuf {
    let home = std::env::var("HOME").unwrap_or_else(|_| ".".to_string());
    PathBuf::from(home)
        .join(".nexus")
        .join("desktop-backend")
        .join("computer-control")
}

fn show_desktop_notification(message: &str) {
    #[cfg(target_os = "linux")]
    let _ = Command::new("notify-send")
        .arg("Nexus OS")
        .arg(message)
        .output();

    #[cfg(target_os = "macos")]
    let _ = Command::new("osascript")
        .arg("-e")
        .arg(format!(
            "display notification {:?} with title \"Nexus OS\"",
            message
        ))
        .output();

    #[cfg(target_os = "windows")]
    let _ = Command::new("powershell")
        .args([
            "-NoProfile",
            "-Command",
            &format!(
                "Add-Type -AssemblyName PresentationFramework; [System.Windows.MessageBox]::Show({:?}, 'Nexus OS')",
                message
            ),
        ])
        .output();
}

fn run_backend_computer_action(
    state: &AppState,
    session_id: &str,
    description: &str,
    max_steps: u32,
    cancelled: &Arc<AtomicBool>,
) -> Result<String, String> {
    let workspace = desktop_control_workspace().join(session_id);
    std::fs::create_dir_all(&workspace)
        .map_err(|e| format!("failed to create {}: {e}", workspace.display()))?;

    {
        let mut engine = state
            .computer_control
            .lock()
            .unwrap_or_else(|p| p.into_inner());
        if !engine.is_enabled() {
            engine.enable();
        }
    }

    let mut actions_taken = Vec::new();
    let max_steps = max_steps.max(1);
    for step in 0..max_steps {
        if cancelled.load(Ordering::SeqCst) {
            return Ok(format!(
                "Computer action '{session_id}' cancelled after {} steps",
                actions_taken.len()
            ));
        }

        let screenshot = capture_and_store_screen(
            &workspace,
            None,
            &format!("session-{session_id}-step-{step}"),
        )?;
        let analysis =
            analyze_stored_screenshot_for_backend(&screenshot, description, actions_taken.last())?;
        if analysis.action == "done" {
            return Ok(format!(
                "Computer action complete. Final screenshot: {}. Actions: {}",
                screenshot.display(),
                if actions_taken.is_empty() {
                    "none".to_string()
                } else {
                    actions_taken.join(", ")
                }
            ));
        }

        let action = backend_decision_to_input_action(&analysis)?;
        let label = action.label();
        {
            let mut engine = state
                .computer_control
                .lock()
                .unwrap_or_else(|p| p.into_inner());
            engine.execute(action)?;
        }
        actions_taken.push(label);
        std::thread::sleep(std::time::Duration::from_millis(500));
        let _ = capture_and_store_screen(
            &workspace,
            None,
            &format!("session-{session_id}-step-{step}-after"),
        );
    }

    Ok(format!(
        "Computer action stopped after reaching max_steps={max_steps}. Actions: {}",
        actions_taken.join(", ")
    ))
}

#[derive(Debug, Clone, Serialize, Deserialize)]
struct BackendComputerDecision {
    action: String,
    x: Option<u32>,
    y: Option<u32>,
    text: Option<String>,
    key: Option<String>,
    direction: Option<String>,
    amount: Option<u32>,
}

#[cfg_attr(test, allow(unused_variables))]
fn analyze_stored_screenshot_for_backend(
    screenshot: &std::path::Path,
    description: &str,
    previous_action: Option<&String>,
) -> Result<BackendComputerDecision, String> {
    #[cfg(test)]
    {
        if previous_action.is_none() && description.contains("click once") {
            return Ok(BackendComputerDecision {
                action: "click".to_string(),
                x: Some(10),
                y: Some(10),
                text: None,
                key: None,
                direction: None,
                amount: None,
            });
        }
        return Ok(BackendComputerDecision {
            action: "done".to_string(),
            x: None,
            y: None,
            text: None,
            key: None,
            direction: None,
            amount: None,
        });
    }

    #[allow(unreachable_code)]
    {
        let prompt = if let Some(previous_action) = previous_action {
            format!(
                "You are controlling a computer. Previous action: {previous_action}. New screen: [screenshot]. Goal: {description}. Is the goal complete? If not, what's the next action? Respond with JSON: {{\"action\":\"click|type|key|scroll|done\",\"x\":number,\"y\":number,\"text\":string,\"key\":string,\"direction\":string,\"amount\":number}}"
            )
        } else {
            format!(
                "You are controlling a computer. Current screen: [screenshot]. Goal: {description}. What is the next mouse/keyboard action to take? Respond with JSON: {{\"action\":\"click|type|key|scroll|done\",\"x\":number,\"y\":number,\"text\":string,\"key\":string,\"direction\":string,\"amount\":number}}"
            )
        };
        let provider = OllamaProvider::from_env();
        let bytes = std::fs::read(screenshot)
            .map_err(|e| format!("failed to read screenshot {}: {e}", screenshot.display()))?;
        let image_base64 = base64::engine::general_purpose::STANDARD.encode(bytes);
        let raw = provider
            .query_with_image(&prompt, &image_base64, "")
            .map_err(agent_error)?;
        let candidate = raw
            .trim()
            .trim_start_matches("```json")
            .trim_start_matches("```")
            .trim_end_matches("```")
            .trim();
        serde_json::from_str::<BackendComputerDecision>(candidate)
            .map_err(|e| format!("failed to parse computer-use decision: {e}"))
    }
}

fn backend_decision_to_input_action(
    decision: &BackendComputerDecision,
) -> Result<InputAction, String> {
    match decision.action.as_str() {
        "click" => Ok(InputAction::Click {
            x: decision.x.ok_or_else(|| "decision missing x".to_string())?,
            y: decision.y.ok_or_else(|| "decision missing y".to_string())?,
            button: nexus_kernel::computer_control::MouseButton::Left,
        }),
        "type" => Ok(InputAction::Type {
            text: decision
                .text
                .clone()
                .ok_or_else(|| "decision missing text".to_string())?,
        }),
        "key" => Ok(InputAction::KeyPress {
            key: decision
                .key
                .clone()
                .ok_or_else(|| "decision missing key".to_string())?,
            modifiers: vec![],
        }),
        "scroll" => Ok(InputAction::Scroll {
            direction: decision
                .direction
                .clone()
                .unwrap_or_else(|| "down".to_string()),
            amount: decision.amount.unwrap_or(1),
        }),
        other => Err(format!("unsupported computer-use action '{other}'")),
    }
}

pub fn computer_control_capture_screen(
    state: &AppState,
    region: Option<String>,
) -> Result<String, String> {
    let engine = state
        .computer_control
        .lock()
        .unwrap_or_else(|p| p.into_inner());
    if !engine.is_enabled() {
        return Err("Computer control engine is disabled".into());
    }
    let region_parsed: Option<nexus_kernel::computer_control::ScreenRegion> = match region {
        Some(r) => Some(serde_json::from_str(&r).map_err(|e| e.to_string())?),
        None => None,
    };
    let result = engine.capture_screen(region_parsed.as_ref());
    serde_json::to_string(&result).map_err(|e| e.to_string())
}

pub fn computer_control_execute_action(
    state: &AppState,
    action_json: String,
) -> Result<String, String> {
    let mut engine = state
        .computer_control
        .lock()
        .unwrap_or_else(|p| p.into_inner());
    if !engine.is_enabled() {
        return Err("Computer control engine is disabled".into());
    }
    let action: InputAction = serde_json::from_str(&action_json).map_err(|e| e.to_string())?;
    let result = engine.execute(action);
    state.log_event(
        Uuid::nil(),
        EventType::UserAction,
        json!({
            "source": "computer-control",
            "action": "execute",
            "success": result.is_ok(),
        }),
    );
    match result {
        Ok(record) => serde_json::to_string(&record).map_err(|e| e.to_string()),
        Err(e) => Err(e),
    }
}

