pub fn learning_execute_challenge(
    challenge_id: String,
    code: String,
    language: String,
) -> Result<String, String> {
    if code.trim().is_empty() {
        return Err("Code is empty".to_string());
    }

    // Basic static analysis checks for Rust challenges
    let result = match language.as_str() {
        "rust" => {
            let mut issues: Vec<String> = Vec::new();
            let mut passed = true;

            // Check for unimplemented code
            if code.contains("todo!()") || code.contains("unimplemented!()") {
                issues.push(
                    "Code contains unimplemented sections (todo!() or unimplemented!())"
                        .to_string(),
                );
                passed = false;
            }

            // Check for empty function bodies
            if code.contains("{}") && !code.contains("// empty") {
                let brace_count = code.matches('{').count();
                let empty_brace_count = code.matches("{}").count();
                if empty_brace_count > 0 && empty_brace_count as f64 / brace_count as f64 > 0.5 {
                    issues.push("Most function bodies are empty".to_string());
                    passed = false;
                }
            }

            // Check for required patterns based on challenge
            match challenge_id.as_str() {
                "cap-check" => {
                    if !code.contains("capability") && !code.contains("Capability") {
                        issues.push("Expected capability checking logic".to_string());
                        passed = false;
                    }
                    if !code.contains("Result") && !code.contains("Option") {
                        issues.push("Expected error handling with Result or Option".to_string());
                        passed = false;
                    }
                }
                "audit-trail" => {
                    if !code.contains("AuditTrail") && !code.contains("audit") {
                        issues.push("Expected audit trail usage".to_string());
                        passed = false;
                    }
                    if !code.contains("append") && !code.contains("log") && !code.contains("record")
                    {
                        issues.push("Expected event recording/appending logic".to_string());
                        passed = false;
                    }
                }
                "fuel-budget" => {
                    if !code.contains("fuel") && !code.contains("Fuel") && !code.contains("budget")
                    {
                        issues.push("Expected fuel budget tracking".to_string());
                        passed = false;
                    }
                }
                _ => {
                    // Generic: must have some structure
                    if code.lines().filter(|l| !l.trim().is_empty()).count() < 5 {
                        issues.push(
                            "Solution is too short — expected at least 5 lines of code".to_string(),
                        );
                        passed = false;
                    }
                }
            }

            // Check for basic Rust syntax patterns
            if !code.contains("fn ") && !code.contains("struct ") && !code.contains("impl ") {
                issues.push("Expected Rust code with function/struct/impl definitions".to_string());
                passed = false;
            }

            json!({
                "passed": passed,
                "challenge_id": challenge_id,
                "feedback": if passed {
                    "Challenge passed! Your code meets the structural and pattern requirements.".to_string()
                } else {
                    format!("Challenge failed:\n{}", issues.iter().map(|i| format!("  • {i}")).collect::<Vec<_>>().join("\n"))
                },
                "issues": issues,
            })
        }
        _ => {
            // For non-Rust: basic length and structure check
            let line_count = code.lines().filter(|l| !l.trim().is_empty()).count();
            let passed = line_count >= 5 && !code.contains("todo!()");
            json!({
                "passed": passed,
                "challenge_id": challenge_id,
                "feedback": if passed {
                    "Challenge passed!".to_string()
                } else {
                    "Challenge failed: code is too short or contains placeholder markers".to_string()
                },
                "issues": [],
            })
        }
    };

    serde_json::to_string(&result).map_err(|e| format!("json error: {e}"))
}

// ── Notes App ─────────────────────────────────────────────────────────

fn notes_dir() -> Result<PathBuf, String> {
    let dir = nexus_data_dir()?.join("notes");
    if !dir.exists() {
        std::fs::create_dir_all(&dir).map_err(|e| format!("cannot create notes dir: {e}"))?;
    }
    Ok(dir)
}

pub fn notes_list(state: &AppState) -> Result<String, String> {
    state.log_event(
        uuid::Uuid::nil(),
        EventType::UserAction,
        json!({"action": "notes_list"}),
    );

    let dir = notes_dir()?;
    let mut notes = Vec::new();

    if dir.exists() {
        let read_dir = std::fs::read_dir(&dir).map_err(|e| format!("read_dir failed: {e}"))?;
        for entry in read_dir {
            let entry = entry.map_err(|e| format!("entry error: {e}"))?;
            let path = entry.path();
            if path.extension().and_then(|e| e.to_str()) == Some("json") {
                let content =
                    std::fs::read_to_string(&path).map_err(|e| format!("read failed: {e}"))?;
                if let Ok(note) = serde_json::from_str::<serde_json::Value>(&content) {
                    notes.push(note);
                }
            }
        }
    }

    serde_json::to_string(&notes).map_err(|e| format!("json error: {e}"))
}

pub fn notes_get(state: &AppState, id: String) -> Result<String, String> {
    state.log_event(
        uuid::Uuid::nil(),
        EventType::UserAction,
        json!({"action": "notes_get", "id": id}),
    );

    let path = notes_dir()?.join(format!("{id}.json"));
    if !path.exists() {
        return Err(format!("note not found: {id}"));
    }
    std::fs::read_to_string(&path).map_err(|e| format!("read failed: {e}"))
}

pub fn notes_save(
    state: &AppState,
    id: String,
    title: String,
    content: String,
    folder_id: String,
    tags_json: String,
) -> Result<String, String> {
    state.log_event(
        uuid::Uuid::nil(),
        EventType::UserAction,
        json!({"action": "notes_save", "id": id, "title": title}),
    );

    let dir = notes_dir()?;
    let path = dir.join(format!("{id}.json"));

    let tags: Vec<String> = serde_json::from_str(&tags_json).unwrap_or_default();

    // Load existing note to preserve createdAt, or create new timestamp
    let now = std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .map(|d| d.as_millis() as u64)
        .unwrap_or(0);

    let created_at = if path.exists() {
        let existing = std::fs::read_to_string(&path).unwrap_or_default();
        serde_json::from_str::<serde_json::Value>(&existing)
            .ok()
            .and_then(|v| v["createdAt"].as_u64())
            .unwrap_or(now)
    } else {
        now
    };

    let word_count = content.split_whitespace().count();

    let note = json!({
        "id": id,
        "title": title,
        "content": content,
        "folderId": folder_id,
        "tags": tags,
        "createdAt": created_at,
        "updatedAt": now,
        "wordCount": word_count,
    });

    let serialized = serde_json::to_string_pretty(&note).map_err(|e| format!("json error: {e}"))?;
    std::fs::write(&path, &serialized).map_err(|e| format!("write failed: {e}"))?;
    Ok(serialized)
}

pub fn notes_delete(state: &AppState, id: String) -> Result<String, String> {
    state.log_event(
        uuid::Uuid::nil(),
        EventType::UserAction,
        json!({"action": "notes_delete", "id": id}),
    );

    let path = notes_dir()?.join(format!("{id}.json"));
    if path.exists() {
        std::fs::remove_file(&path).map_err(|e| format!("delete failed: {e}"))?;
    }
    Ok("ok".to_string())
}

// ── Email Client (local drafts) ───────────────────────────────────────

fn emails_dir() -> Result<PathBuf, String> {
    let dir = nexus_data_dir()?.join("emails");
    if !dir.exists() {
        std::fs::create_dir_all(&dir).map_err(|e| format!("cannot create emails dir: {e}"))?;
    }
    Ok(dir)
}

pub fn email_list(state: &AppState) -> Result<String, String> {
    state.log_event(
        uuid::Uuid::nil(),
        EventType::UserAction,
        json!({"action": "email_list"}),
    );
    let dir = emails_dir()?;
    let mut emails = Vec::new();
    if dir.exists() {
        let read_dir = std::fs::read_dir(&dir).map_err(|e| format!("read_dir failed: {e}"))?;
        for entry in read_dir {
            let entry = entry.map_err(|e| format!("entry error: {e}"))?;
            let path = entry.path();
            if path.extension().and_then(|e| e.to_str()) == Some("json") {
                let content =
                    std::fs::read_to_string(&path).map_err(|e| format!("read failed: {e}"))?;
                if let Ok(email) = serde_json::from_str::<serde_json::Value>(&content) {
                    emails.push(email);
                }
            }
        }
    }
    serde_json::to_string(&emails).map_err(|e| format!("json error: {e}"))
}

pub fn email_save(state: &AppState, id: String, data_json: String) -> Result<String, String> {
    state.log_event(
        uuid::Uuid::nil(),
        EventType::UserAction,
        json!({"action": "email_save", "id": id}),
    );
    let dir = emails_dir()?;
    let path = dir.join(format!("{id}.json"));
    // Validate JSON
    let _parsed: serde_json::Value =
        serde_json::from_str(&data_json).map_err(|e| format!("invalid json: {e}"))?;
    std::fs::write(&path, &data_json).map_err(|e| format!("write failed: {e}"))?;
    Ok("ok".to_string())
}

pub fn email_delete(state: &AppState, id: String) -> Result<String, String> {
    state.log_event(
        uuid::Uuid::nil(),
        EventType::UserAction,
        json!({"action": "email_delete", "id": id}),
    );
    let path = emails_dir()?.join(format!("{id}.json"));
    if path.exists() {
        std::fs::remove_file(&path).map_err(|e| format!("delete failed: {e}"))?;
    }
    Ok("ok".to_string())
}

// ── Email OAuth2 (Gmail / Outlook via REST API) ───────────────────────

fn email_oauth_dir() -> Result<PathBuf, String> {
    let dir = nexus_data_dir()?.join("email_oauth");
    if !dir.exists() {
        std::fs::create_dir_all(&dir).map_err(|e| format!("cannot create email_oauth dir: {e}"))?;
    }
    Ok(dir)
}

fn read_messaging_token(platform: &str) -> Result<String, String> {
    let path = nexus_data_dir()?
        .join("messaging_tokens")
        .join(format!("{platform}.json"));
    if !path.exists() {
        return Err(format!(
            "{platform} not configured — add bot token in Messaging settings"
        ));
    }
    let content = std::fs::read_to_string(&path).map_err(|e| format!("read: {e}"))?;
    let data: serde_json::Value =
        serde_json::from_str(&content).map_err(|e| format!("parse: {e}"))?;
    data.get("token")
        .and_then(|v| v.as_str())
        .map(|s| s.to_string())
        .ok_or_else(|| format!("no token for {platform}"))
}

fn read_oauth_setting(key: &str) -> Result<String, String> {
    let path = nexus_data_dir()?.join("oauth_settings.json");
    if !path.exists() {
        return Err("no oauth settings file".to_string());
    }
    let content = std::fs::read_to_string(&path).map_err(|e| format!("read: {e}"))?;
    let data: serde_json::Value =
        serde_json::from_str(&content).map_err(|e| format!("parse: {e}"))?;
    data.get(key)
        .and_then(|v| v.as_str())
        .map(|s| s.to_string())
        .ok_or_else(|| format!("key {key} not found"))
}

pub fn email_start_oauth(state: &AppState, provider: String) -> Result<String, String> {
    state.log_event(
        uuid::Uuid::nil(),
        EventType::UserAction,
        json!({"action": "email_start_oauth", "provider": provider}),
    );

    // Client IDs from env vars or local config file
    let client_id = match provider.as_str() {
        "gmail" => std::env::var("NEXUS_GMAIL_CLIENT_ID")
            .or_else(|_| read_oauth_setting("gmail_client_id"))
            .unwrap_or_default(),
        "outlook" => std::env::var("NEXUS_OUTLOOK_CLIENT_ID")
            .or_else(|_| read_oauth_setting("outlook_client_id"))
            .unwrap_or_default(),
        _ => return Err(format!("Unknown email provider: {provider}")),
    };

    if client_id.is_empty() {
        return Err(format!(
            "No client ID configured for {provider}. Set NEXUS_{}_CLIENT_ID env var or configure in Settings.",
            provider.to_uppercase()
        ));
    }

    let csrf_token = uuid::Uuid::new_v4().to_string();
    let redirect_uri = "http://localhost:19823/oauth/callback";

    let auth_url = match provider.as_str() {
        "gmail" => format!(
            "https://accounts.google.com/o/oauth2/v2/auth?\
             client_id={client_id}&redirect_uri={redirect_uri}&response_type=code&\
             scope=https://www.googleapis.com/auth/gmail.modify&\
             state={csrf_token}&access_type=offline&prompt=consent"
        ),
        "outlook" => format!(
            "https://login.microsoftonline.com/common/oauth2/v2.0/authorize?\
             client_id={client_id}&redirect_uri={redirect_uri}&response_type=code&\
             scope=Mail.ReadWrite+Mail.Send+offline_access&state={csrf_token}"
        ),
        _ => unreachable!(),
    };

    // Open browser for OAuth
    let _ = open::that(&auth_url);

    // Start a local listener to catch the callback
    let listener = std::net::TcpListener::bind("127.0.0.1:19823")
        .map_err(|e| format!("Cannot start OAuth listener: {e}"))?;
    listener
        .set_nonblocking(false)
        .map_err(|e| format!("set_nonblocking: {e}"))?;

    // Wait for the callback (with timeout)
    let deadline = std::time::Instant::now() + std::time::Duration::from_secs(120);
    let mut auth_code = String::new();
    while std::time::Instant::now() < deadline {
        match listener.accept() {
            Ok((mut stream, _)) => {
                use std::io::{Read as IoRead, Write as IoWrite};
                let mut buf = [0u8; 4096];
                let n = stream.read(&mut buf).unwrap_or(0);
                let request = String::from_utf8_lossy(&buf[..n]).to_string();

                // Parse the code from GET /?code=XXX&state=YYY
                if let Some(query_start) = request.find("GET /?") {
                    let query = &request[query_start + 6..];
                    if let Some(end) = query.find(' ') {
                        let params = &query[..end];
                        for param in params.split('&') {
                            let parts: Vec<&str> = param.splitn(2, '=').collect();
                            if parts.len() == 2 && parts[0] == "code" {
                                auth_code = parts[1].to_string();
                            }
                        }
                    }
                }

                // Send a nice response page
                let body = "<html><body style=\"font-family:system-ui;text-align:center;padding:60px;background:#0f172a;color:#e2e8f0\">\
                    <h1>&#10003; Connected!</h1>\
                    <p>You can close this tab and return to Nexus OS.</p>\
                    </body></html>";
                let response = format!(
                    "HTTP/1.1 200 OK\r\nContent-Type: text/html\r\nContent-Length: {}\r\n\r\n{}",
                    body.len(),
                    body
                );
                let _ = stream.write_all(response.as_bytes());
                break;
            }
            Err(_) => {
                std::thread::sleep(std::time::Duration::from_millis(200));
            }
        }
    }

    if auth_code.is_empty() {
        return Err("OAuth flow timed out or no auth code received".to_string());
    }

    // Exchange code for tokens
    let client_secret = match provider.as_str() {
        "gmail" => std::env::var("NEXUS_GMAIL_CLIENT_SECRET")
            .or_else(|_| read_oauth_setting("gmail_client_secret"))
            .unwrap_or_default(),
        "outlook" => std::env::var("NEXUS_OUTLOOK_CLIENT_SECRET")
            .or_else(|_| read_oauth_setting("outlook_client_secret"))
            .unwrap_or_default(),
        _ => String::new(),
    };

    let token_url = match provider.as_str() {
        "gmail" => "https://oauth2.googleapis.com/token",
        "outlook" => "https://login.microsoftonline.com/common/oauth2/v2.0/token",
        _ => unreachable!(),
    };

    let token_resp = block_on_async(async {
        reqwest::Client::new()
            .post(token_url)
            .form(&[
                ("code", auth_code.as_str()),
                ("client_id", client_id.as_str()),
                ("client_secret", client_secret.as_str()),
                ("redirect_uri", redirect_uri),
                ("grant_type", "authorization_code"),
            ])
            .send()
            .await
            .map_err(|e| format!("token exchange: {e}"))?
            .text()
            .await
            .map_err(|e| format!("token body: {e}"))
    })?;

    let token_json: serde_json::Value =
        serde_json::from_str(&token_resp).map_err(|e| format!("token parse: {e}"))?;

    // Store tokens encrypted in local file
    let token_path = email_oauth_dir()?.join(format!("{provider}_tokens.json"));
    let token_data = json!({
        "provider": provider,
        "access_token": token_json.get("access_token").and_then(|v| v.as_str()).unwrap_or(""),
        "refresh_token": token_json.get("refresh_token").and_then(|v| v.as_str()).unwrap_or(""),
        "expires_at": chrono::Utc::now().timestamp() + token_json.get("expires_in").and_then(|v| v.as_i64()).unwrap_or(3600),
        "connected_at": chrono::Utc::now().to_rfc3339(),
    });
    std::fs::write(
        &token_path,
        serde_json::to_string_pretty(&token_data).unwrap(),
    )
    .map_err(|e| format!("write tokens: {e}"))?;

    serde_json::to_string(&json!({
        "status": "connected",
        "provider": provider,
    }))
    .map_err(|e| format!("json: {e}"))
}

pub fn email_oauth_status(state: &AppState) -> Result<String, String> {
    state.log_event(
        uuid::Uuid::nil(),
        EventType::UserAction,
        json!({"action": "email_oauth_status"}),
    );
    let dir = email_oauth_dir()?;
    let mut statuses = Vec::new();
    for provider in &["gmail", "outlook"] {
        let path = dir.join(format!("{provider}_tokens.json"));
        if path.exists() {
            if let Ok(content) = std::fs::read_to_string(&path) {
                if let Ok(data) = serde_json::from_str::<serde_json::Value>(&content) {
                    let expires_at = data.get("expires_at").and_then(|v| v.as_i64()).unwrap_or(0);
                    let valid = chrono::Utc::now().timestamp() < expires_at;
                    statuses.push(json!({
                        "provider": provider,
                        "connected": true,
                        "token_valid": valid,
                        "connected_at": data.get("connected_at"),
                    }));
                    continue;
                }
            }
        }
        statuses.push(json!({
            "provider": provider,
            "connected": false,
            "token_valid": false,
        }));
    }
    serde_json::to_string(&statuses).map_err(|e| format!("json: {e}"))
}

fn get_email_access_token(provider: &str) -> Result<String, String> {
    let path = email_oauth_dir()?.join(format!("{provider}_tokens.json"));
    if !path.exists() {
        return Err(format!("{provider} not connected"));
    }
    let content = std::fs::read_to_string(&path).map_err(|e| format!("read: {e}"))?;
    let data: serde_json::Value =
        serde_json::from_str(&content).map_err(|e| format!("parse: {e}"))?;
    let token = data
        .get("access_token")
        .and_then(|v| v.as_str())
        .ok_or_else(|| "no access_token".to_string())?
        .to_string();
    Ok(token)
}

pub fn email_fetch_messages(
    state: &AppState,
    provider: String,
    folder: String,
    page: u32,
) -> Result<String, String> {
    state.log_event(
        uuid::Uuid::nil(),
        EventType::UserAction,
        json!({"action": "email_fetch_messages", "provider": provider, "folder": folder}),
    );
    let token = get_email_access_token(&provider)?;
    let max_results = 20u32;

    let result = block_on_async(async {
        match provider.as_str() {
            "gmail" => {
                let label = match folder.as_str() {
                    "inbox" => "INBOX",
                    "sent" => "SENT",
                    "drafts" => "DRAFT",
                    "trash" => "TRASH",
                    "starred" => "STARRED",
                    _ => "INBOX",
                };
                let url = format!(
                    "https://gmail.googleapis.com/gmail/v1/users/me/messages?labelIds={label}&maxResults={max_results}"
                );
                let resp = reqwest::Client::new()
                    .get(&url)
                    .bearer_auth(&token)
                    .send()
                    .await
                    .map_err(|e| format!("gmail list: {e}"))?;
                let body = resp.text().await.map_err(|e| format!("gmail body: {e}"))?;
                let list: serde_json::Value =
                    serde_json::from_str(&body).map_err(|e| format!("gmail parse: {e}"))?;

                let mut emails = Vec::new();
                if let Some(messages) = list.get("messages").and_then(|m| m.as_array()) {
                    for msg in messages.iter().take(max_results as usize) {
                        if let Some(id) = msg.get("id").and_then(|v| v.as_str()) {
                            // Fetch each message detail
                            let detail_url = format!(
                                "https://gmail.googleapis.com/gmail/v1/users/me/messages/{id}?format=metadata&metadataHeaders=From&metadataHeaders=To&metadataHeaders=Subject&metadataHeaders=Date"
                            );
                            let detail_resp = reqwest::Client::new()
                                .get(&detail_url)
                                .bearer_auth(&token)
                                .send()
                                .await;
                            if let Ok(resp) = detail_resp {
                                if let Ok(text) = resp.text().await {
                                    if let Ok(detail) =
                                        serde_json::from_str::<serde_json::Value>(&text)
                                    {
                                        let headers = detail
                                            .get("payload")
                                            .and_then(|p| p.get("headers"))
                                            .and_then(|h| h.as_array());
                                        let mut from = String::new();
                                        let mut to = String::new();
                                        let mut subject = String::new();
                                        if let Some(hdrs) = headers {
                                            for h in hdrs {
                                                let name = h
                                                    .get("name")
                                                    .and_then(|v| v.as_str())
                                                    .unwrap_or("");
                                                let value = h
                                                    .get("value")
                                                    .and_then(|v| v.as_str())
                                                    .unwrap_or("");
                                                match name {
                                                    "From" => from = value.to_string(),
                                                    "To" => to = value.to_string(),
                                                    "Subject" => subject = value.to_string(),
                                                    _ => {}
                                                }
                                            }
                                        }
                                        let snippet = detail
                                            .get("snippet")
                                            .and_then(|v| v.as_str())
                                            .unwrap_or("")
                                            .to_string();
                                        let label_ids =
                                            detail.get("labelIds").and_then(|v| v.as_array());
                                        let unread = label_ids
                                            .map(|l| l.iter().any(|v| v.as_str() == Some("UNREAD")))
                                            .unwrap_or(false);
                                        let internal_date = detail
                                            .get("internalDate")
                                            .and_then(|v| v.as_str())
                                            .and_then(|s| s.parse::<i64>().ok())
                                            .unwrap_or(0);

                                        emails.push(json!({
                                            "id": id,
                                            "threadId": detail.get("threadId").and_then(|v| v.as_str()).unwrap_or(id),
                                            "from": {"name": from.split('<').next().unwrap_or(&from).trim(), "email": from},
                                            "to": [{"name": to.split('<').next().unwrap_or(&to).trim(), "email": to}],
                                            "subject": subject,
                                            "body": snippet,
                                            "timestamp": internal_date,
                                            "read": !unread,
                                            "starred": label_ids.map(|l| l.iter().any(|v| v.as_str() == Some("STARRED"))).unwrap_or(false),
                                            "folder": folder,
                                            "priority": "normal",
                                            "category": "primary",
                                            "labels": [],
                                            "source": "gmail",
                                        }));
                                    }
                                }
                            }
                        }
                    }
                }
                serde_json::to_string(&emails).map_err(|e| format!("serialize: {e}"))
            }
            "outlook" => {
                let folder_path = match folder.as_str() {
                    "inbox" => "inbox",
                    "sent" => "sentitems",
                    "drafts" => "drafts",
                    "trash" => "deleteditems",
                    _ => "inbox",
                };
                let url = format!(
                    "https://graph.microsoft.com/v1.0/me/mailFolders/{folder_path}/messages?$top={max_results}&$skip={}&$orderby=receivedDateTime+desc",
                    page * max_results
                );
                let resp = reqwest::Client::new()
                    .get(&url)
                    .bearer_auth(&token)
                    .send()
                    .await
                    .map_err(|e| format!("outlook list: {e}"))?;
                let body = resp
                    .text()
                    .await
                    .map_err(|e| format!("outlook body: {e}"))?;
                let data: serde_json::Value =
                    serde_json::from_str(&body).map_err(|e| format!("outlook parse: {e}"))?;

                let mut emails = Vec::new();
                if let Some(messages) = data.get("value").and_then(|m| m.as_array()) {
                    for msg in messages {
                        let from_obj = msg.get("from").and_then(|f| f.get("emailAddress"));
                        let from_name = from_obj
                            .and_then(|f| f.get("name"))
                            .and_then(|v| v.as_str())
                            .unwrap_or("");
                        let from_email = from_obj
                            .and_then(|f| f.get("address"))
                            .and_then(|v| v.as_str())
                            .unwrap_or("");
                        let subject = msg.get("subject").and_then(|v| v.as_str()).unwrap_or("");
                        let preview = msg
                            .get("bodyPreview")
                            .and_then(|v| v.as_str())
                            .unwrap_or("");
                        let is_read = msg.get("isRead").and_then(|v| v.as_bool()).unwrap_or(true);
                        let received = msg
                            .get("receivedDateTime")
                            .and_then(|v| v.as_str())
                            .unwrap_or("");
                        let id = msg.get("id").and_then(|v| v.as_str()).unwrap_or("");

                        emails.push(json!({
                            "id": id,
                            "threadId": msg.get("conversationId").and_then(|v| v.as_str()).unwrap_or(id),
                            "from": {"name": from_name, "email": from_email},
                            "to": [],
                            "subject": subject,
                            "body": preview,
                            "timestamp": chrono::DateTime::parse_from_rfc3339(received).map(|d| d.timestamp_millis()).unwrap_or(0),
                            "read": is_read,
                            "starred": msg.get("flag").and_then(|f| f.get("flagStatus")).and_then(|v| v.as_str()) == Some("flagged"),
                            "folder": folder,
                            "priority": if msg.get("importance").and_then(|v| v.as_str()) == Some("high") { "high" } else { "normal" },
                            "category": "primary",
                            "labels": [],
                            "source": "outlook",
                        }));
                    }
                }
                serde_json::to_string(&emails).map_err(|e| format!("serialize: {e}"))
            }
            _ => Err(format!("Unknown provider: {provider}")),
        }
    })?;
    Ok(result)
}

pub fn email_send_message(
    state: &AppState,
    provider: String,
    to: String,
    subject: String,
    body: String,
) -> Result<String, String> {
    state.log_event(
        uuid::Uuid::nil(),
        EventType::UserAction,
        json!({"action": "email_send", "provider": provider, "to": to}),
    );
    let token = get_email_access_token(&provider)?;

    let result = block_on_async(async {
        match provider.as_str() {
            "gmail" => {
                let raw_message = format!(
                    "To: {to}\r\nSubject: {subject}\r\nContent-Type: text/html; charset=UTF-8\r\n\r\n{body}"
                );
                let encoded = base64::Engine::encode(
                    &base64::engine::general_purpose::URL_SAFE_NO_PAD,
                    raw_message.as_bytes(),
                );
                let resp = reqwest::Client::new()
                    .post("https://gmail.googleapis.com/gmail/v1/users/me/messages/send")
                    .bearer_auth(&token)
                    .json(&json!({"raw": encoded}))
                    .send()
                    .await
                    .map_err(|e| format!("gmail send: {e}"))?;
                let status = resp.status();
                let text = resp.text().await.unwrap_or_default();
                if status.is_success() {
                    Ok(json!({"status": "sent", "provider": "gmail"}).to_string())
                } else {
                    Err(format!("Gmail send failed ({status}): {text}"))
                }
            }
            "outlook" => {
                let mail = json!({
                    "message": {
                        "subject": subject,
                        "body": {"contentType": "HTML", "content": body},
                        "toRecipients": [{"emailAddress": {"address": to}}]
                    },
                    "saveToSentItems": true
                });
                let resp = reqwest::Client::new()
                    .post("https://graph.microsoft.com/v1.0/me/sendMail")
                    .bearer_auth(&token)
                    .json(&mail)
                    .send()
                    .await
                    .map_err(|e| format!("outlook send: {e}"))?;
                let status = resp.status();
                if status.is_success() || status.as_u16() == 202 {
                    Ok(json!({"status": "sent", "provider": "outlook"}).to_string())
                } else {
                    let text = resp.text().await.unwrap_or_default();
                    Err(format!("Outlook send failed ({status}): {text}"))
                }
            }
            _ => Err(format!("Unknown provider: {provider}")),
        }
    })?;
    Ok(result)
}

pub fn email_search_messages(
    state: &AppState,
    provider: String,
    query: String,
) -> Result<String, String> {
    state.log_event(
        uuid::Uuid::nil(),
        EventType::UserAction,
        json!({"action": "email_search", "provider": provider, "query": query}),
    );
    let token = get_email_access_token(&provider)?;

    let result = block_on_async(async {
        match provider.as_str() {
            "gmail" => {
                let url = format!(
                    "https://gmail.googleapis.com/gmail/v1/users/me/messages?q={}&maxResults=20",
                    urlencoding::encode(&query)
                );
                let resp = reqwest::Client::new()
                    .get(&url)
                    .bearer_auth(&token)
                    .send()
                    .await
                    .map_err(|e| format!("gmail search: {e}"))?;
                resp.text().await.map_err(|e| format!("gmail body: {e}"))
            }
            "outlook" => {
                let url = format!(
                    "https://graph.microsoft.com/v1.0/me/messages?$search=\"{}\"&$top=20",
                    query.replace('"', "\\\"")
                );
                let resp = reqwest::Client::new()
                    .get(&url)
                    .bearer_auth(&token)
                    .send()
                    .await
                    .map_err(|e| format!("outlook search: {e}"))?;
                resp.text().await.map_err(|e| format!("outlook body: {e}"))
            }
            _ => Err(format!("Unknown provider: {provider}")),
        }
    })?;
    Ok(result)
}

pub fn email_disconnect(state: &AppState, provider: String) -> Result<String, String> {
    state.log_event(
        uuid::Uuid::nil(),
        EventType::UserAction,
        json!({"action": "email_disconnect", "provider": provider}),
    );
    let path = email_oauth_dir()?.join(format!("{provider}_tokens.json"));
    if path.exists() {
        std::fs::remove_file(&path).map_err(|e| format!("remove: {e}"))?;
    }
    Ok(json!({"status": "disconnected", "provider": provider}).to_string())
}

// ── Messaging: Real Platform Connections ──────────────────────────────

pub fn messaging_connect_platform(
    state: &AppState,
    platform: String,
    token_value: String,
) -> Result<String, String> {
    state.log_event(
        uuid::Uuid::nil(),
        EventType::UserAction,
        json!({"action": "messaging_connect", "platform": platform}),
    );

    // Store token in messaging tokens file
    let msg_dir = nexus_data_dir()?.join("messaging_tokens");
    if !msg_dir.exists() {
        std::fs::create_dir_all(&msg_dir).map_err(|e| format!("mkdir: {e}"))?;
    }
    let token_path = msg_dir.join(format!("{platform}.json"));
    std::fs::write(
        &token_path,
        serde_json::to_string_pretty(&json!({"token": token_value, "platform": platform, "connected_at": chrono::Utc::now().to_rfc3339()})).unwrap(),
    )
    .map_err(|e| format!("write: {e}"))?;

    // Test connectivity
    let test_result = block_on_async(async {
        match platform.as_str() {
            "telegram" => {
                let url = format!("https://api.telegram.org/bot{}/getMe", token_value);
                let resp = reqwest::Client::new()
                    .get(&url)
                    .send()
                    .await
                    .map_err(|e| format!("telegram test: {e}"))?;
                let body = resp
                    .text()
                    .await
                    .map_err(|e| format!("telegram body: {e}"))?;
                let data: serde_json::Value = serde_json::from_str(&body).unwrap_or_default();
                if data.get("ok").and_then(|v| v.as_bool()).unwrap_or(false) {
                    let bot_name = data
                        .get("result")
                        .and_then(|r| r.get("username"))
                        .and_then(|v| v.as_str())
                        .unwrap_or("unknown");
                    Ok(json!({"connected": true, "bot_name": bot_name}).to_string())
                } else {
                    Err("Invalid Telegram bot token".to_string())
                }
            }
            "slack" => {
                let resp = reqwest::Client::new()
                    .post("https://slack.com/api/auth.test")
                    .bearer_auth(&token_value)
                    .send()
                    .await
                    .map_err(|e| format!("slack test: {e}"))?;
                let body = resp.text().await.map_err(|e| format!("slack body: {e}"))?;
                let data: serde_json::Value = serde_json::from_str(&body).unwrap_or_default();
                if data.get("ok").and_then(|v| v.as_bool()).unwrap_or(false) {
                    let team = data
                        .get("team")
                        .and_then(|v| v.as_str())
                        .unwrap_or("unknown");

                    // Attempt Socket Mode WebSocket connection for real-time events
                    // Requires an app-level token (xapp-*) — if using a bot token, falls back to polling
                    if token_value.starts_with("xapp-") {
                        let ws_resp = reqwest::Client::new()
                            .post("https://slack.com/api/apps.connections.open")
                            .bearer_auth(&token_value)
                            .send()
                            .await;
                        if let Ok(ws_resp) = ws_resp {
                            let ws_data: serde_json::Value =
                                ws_resp.json().await.unwrap_or_default();
                            if let Some(ws_url) = ws_data.get("url").and_then(|v| v.as_str()) {
                                // Store WebSocket URL for the frontend to use
                                let ws_path = msg_dir.join("slack_ws_url.txt");
                                let _ = std::fs::write(&ws_path, ws_url);
                            }
                        }
                    }

                    Ok(json!({"connected": true, "team": team, "realtime": token_value.starts_with("xapp-")}).to_string())
                } else {
                    Err(format!(
                        "Slack auth failed: {}",
                        data.get("error")
                            .and_then(|v| v.as_str())
                            .unwrap_or("unknown")
                    ))
                }
            }
            "discord" => {
                let resp = reqwest::Client::new()
                    .get("https://discord.com/api/v10/users/@me")
                    .header("Authorization", format!("Bot {}", token_value))
                    .send()
                    .await
                    .map_err(|e| format!("discord test: {e}"))?;
                let status = resp.status();
                let body = resp
                    .text()
                    .await
                    .map_err(|e| format!("discord body: {e}"))?;
                if status.is_success() {
                    let data: serde_json::Value = serde_json::from_str(&body).unwrap_or_default();
                    let name = data
                        .get("username")
                        .and_then(|v| v.as_str())
                        .unwrap_or("unknown");
                    Ok(json!({"connected": true, "bot_name": name}).to_string())
                } else {
                    Err(format!("Discord auth failed ({status})"))
                }
            }
            _ => Ok(json!({"connected": true}).to_string()),
        }
    })?;
    Ok(test_result)
}

pub fn messaging_send(
    state: &AppState,
    platform: String,
    channel: String,
    text: String,
) -> Result<String, String> {
    state.log_event(
        uuid::Uuid::nil(),
        EventType::UserAction,
        json!({"action": "messaging_send", "platform": platform, "channel": channel}),
    );

    let token = read_messaging_token(&platform)?;

    let result = block_on_async(async {
        match platform.as_str() {
            "telegram" => {
                let url = format!("https://api.telegram.org/bot{}/sendMessage", token);
                let resp = reqwest::Client::new()
                    .post(&url)
                    .json(&json!({"chat_id": channel, "text": text}))
                    .send()
                    .await
                    .map_err(|e| format!("telegram send: {e}"))?;
                let body = resp.text().await.map_err(|e| format!("body: {e}"))?;
                Ok(body)
            }
            "slack" => {
                let resp = reqwest::Client::new()
                    .post("https://slack.com/api/chat.postMessage")
                    .bearer_auth(&token)
                    .json(&json!({"channel": channel, "text": text}))
                    .send()
                    .await
                    .map_err(|e| format!("slack send: {e}"))?;
                let body = resp.text().await.map_err(|e| format!("body: {e}"))?;
                Ok(body)
            }
            "discord" => {
                let url = format!("https://discord.com/api/v10/channels/{}/messages", channel);
                let resp = reqwest::Client::new()
                    .post(&url)
                    .header("Authorization", format!("Bot {}", token))
                    .json(&json!({"content": text}))
                    .send()
                    .await
                    .map_err(|e| format!("discord send: {e}"))?;
                let body = resp.text().await.map_err(|e| format!("body: {e}"))?;
                Ok(body)
            }
            _ => Err(format!("Unknown platform: {platform}")),
        }
    })?;
    Ok(result)
}

pub fn messaging_poll_messages(
    state: &AppState,
    platform: String,
    channel: String,
    last_id: String,
) -> Result<String, String> {
    state.log_event(
        uuid::Uuid::nil(),
        EventType::UserAction,
        json!({"action": "messaging_poll", "platform": platform}),
    );

    let token = read_messaging_token(&platform)?;

    let result = block_on_async(async {
        match platform.as_str() {
            "telegram" => {
                let offset: i64 = last_id.parse().unwrap_or(0);
                let url = format!(
                    "https://api.telegram.org/bot{}/getUpdates?offset={}&timeout=5&limit=20",
                    token, offset
                );
                let resp = reqwest::Client::new()
                    .get(&url)
                    .send()
                    .await
                    .map_err(|e| format!("telegram poll: {e}"))?;
                resp.text().await.map_err(|e| format!("body: {e}"))
            }
            "slack" => {
                let resp = reqwest::Client::new()
                    .get("https://slack.com/api/conversations.history")
                    .bearer_auth(&token)
                    .query(&[("channel", channel.as_str()), ("limit", "20")])
                    .send()
                    .await
                    .map_err(|e| format!("slack poll: {e}"))?;
                resp.text().await.map_err(|e| format!("body: {e}"))
            }
            "discord" => {
                let url = format!(
                    "https://discord.com/api/v10/channels/{}/messages?limit=20",
                    channel
                );
                let resp = reqwest::Client::new()
                    .get(&url)
                    .header("Authorization", format!("Bot {}", token))
                    .send()
                    .await
                    .map_err(|e| format!("discord poll: {e}"))?;
                resp.text().await.map_err(|e| format!("body: {e}"))
            }
            _ => Err(format!("Unknown platform: {platform}")),
        }
    })?;
    Ok(result)
}

// ── Integration OAuth2 Flow ──────────────────────────────────────────

pub fn integration_start_oauth(state: &AppState, provider_id: String) -> Result<String, String> {
    state.log_event(
        uuid::Uuid::nil(),
        EventType::UserAction,
        json!({"action": "integration_start_oauth", "provider": provider_id}),
    );

    let env_key = format!("NEXUS_{}_CLIENT_ID", provider_id.to_uppercase());
    let client_id = std::env::var(&env_key)
        .or_else(|_| read_oauth_setting(&format!("{provider_id}_client_id")))
        .unwrap_or_default();

    if client_id.is_empty() {
        return Err(format!(
            "No client ID for {provider_id}. Set {env_key} env var or configure in Settings."
        ));
    }

    let redirect_uri = "http://localhost:19824/oauth/callback";
    let csrf = uuid::Uuid::new_v4().to_string();

    let auth_url = match provider_id.as_str() {
        "github" => format!(
            "https://github.com/login/oauth/authorize?client_id={client_id}&redirect_uri={redirect_uri}&state={csrf}&scope=repo,read:org"
        ),
        "gitlab" => format!(
            "https://gitlab.com/oauth/authorize?client_id={client_id}&redirect_uri={redirect_uri}&response_type=code&state={csrf}&scope=api+read_user"
        ),
        "slack" => format!(
            "https://slack.com/oauth/v2/authorize?client_id={client_id}&redirect_uri={redirect_uri}&state={csrf}&scope=chat:write,channels:read,channels:history"
        ),
        "jira" => format!(
            "https://auth.atlassian.com/authorize?audience=api.atlassian.com&client_id={client_id}&scope=read%3Ajira-work%20manage%3Ajira-project&redirect_uri={redirect_uri}&state={csrf}&response_type=code&prompt=consent"
        ),
        _ => return Err(format!("OAuth not supported for {provider_id}. Use token-based auth.")),
    };

    let _ = open::that(&auth_url);

    // Listen for callback on port 19824
    let listener = std::net::TcpListener::bind("127.0.0.1:19824")
        .map_err(|e| format!("Cannot start OAuth listener: {e}"))?;
    let deadline = std::time::Instant::now() + std::time::Duration::from_secs(120);
    let mut auth_code = String::new();

    while std::time::Instant::now() < deadline {
        match listener.accept() {
            Ok((mut stream, _)) => {
                use std::io::{Read as IoRead, Write as IoWrite};
                let mut buf = [0u8; 4096];
                let n = stream.read(&mut buf).unwrap_or(0);
                let request = String::from_utf8_lossy(&buf[..n]).to_string();
                if let Some(qs) = request.find("GET /?") {
                    let query = &request[qs + 6..];
                    if let Some(end) = query.find(' ') {
                        for param in query[..end].split('&') {
                            let parts: Vec<&str> = param.splitn(2, '=').collect();
                            if parts.len() == 2 && parts[0] == "code" {
                                auth_code = parts[1].to_string();
                            }
                        }
                    }
                }
                let body = "<html><body style=\"font-family:system-ui;text-align:center;padding:60px;background:#0f172a;color:#e2e8f0\">\
                    <h1>&#10003; Connected!</h1><p>Return to Nexus OS.</p></body></html>";
                let response = format!(
                    "HTTP/1.1 200 OK\r\nContent-Type: text/html\r\nContent-Length: {}\r\n\r\n{}",
                    body.len(),
                    body
                );
                let _ = stream.write_all(response.as_bytes());
                break;
            }
            Err(_) => std::thread::sleep(std::time::Duration::from_millis(200)),
        }
    }

    if auth_code.is_empty() {
        return Err("OAuth timed out".to_string());
    }

    // Exchange code for token
    let secret_key = format!("NEXUS_{}_CLIENT_SECRET", provider_id.to_uppercase());
    let client_secret = std::env::var(&secret_key)
        .or_else(|_| read_oauth_setting(&format!("{provider_id}_client_secret")))
        .unwrap_or_default();

    let token_result = block_on_async(async {
        let (token_url, use_json) = match provider_id.as_str() {
            "github" => ("https://github.com/login/oauth/access_token", false),
            "gitlab" => ("https://gitlab.com/oauth/token", false),
            "slack" => ("https://slack.com/api/oauth.v2.access", false),
            "jira" => ("https://auth.atlassian.com/oauth/token", true),
            _ => return Err("unsupported".to_string()),
        };

        let client = reqwest::Client::new();
        let resp = if use_json {
            client
                .post(token_url)
                .json(&json!({
                    "grant_type": "authorization_code",
                    "client_id": client_id,
                    "client_secret": client_secret,
                    "code": auth_code,
                    "redirect_uri": redirect_uri,
                }))
                .send()
                .await
        } else {
            client
                .post(token_url)
                .header("Accept", "application/json")
                .form(&[
                    ("client_id", client_id.as_str()),
                    ("client_secret", client_secret.as_str()),
                    ("code", auth_code.as_str()),
                    ("redirect_uri", redirect_uri),
                    ("grant_type", "authorization_code"),
                ])
                .send()
                .await
        };

        let resp = resp.map_err(|e| format!("token request: {e}"))?;
        resp.text().await.map_err(|e| format!("token body: {e}"))
    })?;

    // Store token
    let integration_dir = nexus_data_dir()?.join("integrations");
    if !integration_dir.exists() {
        std::fs::create_dir_all(&integration_dir).map_err(|e| format!("mkdir: {e}"))?;
    }
    let token_path = integration_dir.join(format!("{provider_id}_oauth.json"));
    let token_data = json!({
        "provider": provider_id,
        "token_response": serde_json::from_str::<serde_json::Value>(&token_result).unwrap_or(json!({"raw": token_result})),
        "connected_at": chrono::Utc::now().to_rfc3339(),
    });
    std::fs::write(
        &token_path,
        serde_json::to_string_pretty(&token_data).unwrap(),
    )
    .map_err(|e| format!("write: {e}"))?;

    serde_json::to_string(&json!({"status": "connected", "provider": provider_id}))
        .map_err(|e| format!("json: {e}"))
}

// ── App Store: GitLab API search ─────────────────────────────────────

pub fn marketplace_search_gitlab(query: String) -> Result<String, String> {
    let result = block_on_async(async {
        let url = "https://gitlab.com/api/v4/projects";
        let resp = reqwest::Client::new()
            .get(url)
            .query(&[
                ("search", query.as_str()),
                ("topic", "nexus-agent"),
                ("per_page", "20"),
                ("order_by", "last_activity_at"),
            ])
            .send()
            .await
            .map_err(|e| format!("gitlab search: {e}"))?;
        let body = resp.text().await.map_err(|e| format!("body: {e}"))?;
        let projects: Vec<serde_json::Value> = serde_json::from_str(&body).unwrap_or_default();

        let agents: Vec<serde_json::Value> = projects
            .iter()
            .map(|p| {
                json!({
                    "id": p.get("id").and_then(|v| v.as_i64()).unwrap_or(0).to_string(),
                    "name": p.get("name").and_then(|v| v.as_str()).unwrap_or("Unknown"),
                    "description": p.get("description").and_then(|v| v.as_str()).unwrap_or("Community agent"),
                    "author": p.get("namespace").and_then(|n| n.get("name")).and_then(|v| v.as_str()).unwrap_or("community"),
                    "url": p.get("web_url").and_then(|v| v.as_str()).unwrap_or(""),
                    "stars": p.get("star_count").and_then(|v| v.as_i64()).unwrap_or(0),
                    "source": "gitlab",
                    "autonomy_level": "L2",
                })
            })
            .collect();
        serde_json::to_string(&agents).map_err(|e| format!("json: {e}"))
    })?;
    Ok(result)
}

// ── Agent Output Panel ───────────────────────────────────────────────

pub fn get_agent_outputs(state: &AppState, agent_id: String, limit: u32) -> Result<String, String> {
    state.log_event(
        uuid::Uuid::nil(),
        EventType::UserAction,
        json!({"action": "get_agent_outputs", "agent_id": agent_id}),
    );

    // Pull recent outputs from audit trail for this agent
    let agent_uuid = uuid::Uuid::parse_str(&agent_id).unwrap_or(uuid::Uuid::nil());
    let guard = state.audit.lock().map_err(|e| format!("lock: {e}"))?;
    let all_events = guard.events();
    let filtered: Vec<serde_json::Value> = all_events
        .iter()
        .rev()
        .filter(|e| {
            e.agent_id == agent_uuid
                || e.payload
                    .get("agent_id")
                    .and_then(|v| v.as_str())
                    .map(|s| s == agent_id)
                    .unwrap_or(false)
        })
        .take(limit as usize)
        .map(|e| {
            json!({
                "id": e.event_id.to_string(),
                "time": e.timestamp,
                "action": format!("{:?}", e.event_type),
                "type": "text",
                "content": serde_json::to_string(&e.payload).unwrap_or_default(),
            })
        })
        .collect();
    serde_json::to_string(&filtered).map_err(|e| format!("json: {e}"))
}

// ── Project Manager ───────────────────────────────────────────────────

fn projects_dir() -> Result<PathBuf, String> {
    let dir = nexus_data_dir()?.join("projects");
    if !dir.exists() {
        std::fs::create_dir_all(&dir).map_err(|e| format!("cannot create projects dir: {e}"))?;
    }
    Ok(dir)
}

pub fn project_list(state: &AppState) -> Result<String, String> {
    state.log_event(
        uuid::Uuid::nil(),
        EventType::UserAction,
        json!({"action": "project_list"}),
    );
    let dir = projects_dir()?;
    let mut projects = Vec::new();
    if dir.exists() {
        let read_dir = std::fs::read_dir(&dir).map_err(|e| format!("read_dir failed: {e}"))?;
        for entry in read_dir {
            let entry = entry.map_err(|e| format!("entry error: {e}"))?;
            let path = entry.path();
            if path.extension().and_then(|e| e.to_str()) == Some("json") {
                let content =
                    std::fs::read_to_string(&path).map_err(|e| format!("read failed: {e}"))?;
                if let Ok(project) = serde_json::from_str::<serde_json::Value>(&content) {
                    projects.push(project);
                }
            }
        }
    }
    serde_json::to_string(&projects).map_err(|e| format!("json error: {e}"))
}

pub fn project_get(state: &AppState, id: String) -> Result<String, String> {
    state.log_event(
        uuid::Uuid::nil(),
        EventType::UserAction,
        json!({"action": "project_get", "id": id}),
    );
    let path = projects_dir()?.join(format!("{id}.json"));
    if !path.exists() {
        return Err(format!("project not found: {id}"));
    }
    std::fs::read_to_string(&path).map_err(|e| format!("read failed: {e}"))
}

pub fn project_save(state: &AppState, id: String, data_json: String) -> Result<String, String> {
    state.log_event(
        uuid::Uuid::nil(),
        EventType::UserAction,
        json!({"action": "project_save", "id": id}),
    );
    let dir = projects_dir()?;
    let path = dir.join(format!("{id}.json"));
    let _parsed: serde_json::Value =
        serde_json::from_str(&data_json).map_err(|e| format!("invalid json: {e}"))?;
    std::fs::write(&path, &data_json).map_err(|e| format!("write failed: {e}"))?;
    Ok("ok".to_string())
}

pub fn project_delete(state: &AppState, id: String) -> Result<String, String> {
    state.log_event(
        uuid::Uuid::nil(),
        EventType::UserAction,
        json!({"action": "project_delete", "id": id}),
    );
    let path = projects_dir()?.join(format!("{id}.json"));
    if path.exists() {
        std::fs::remove_file(&path).map_err(|e| format!("delete failed: {e}"))?;
    }
    Ok("ok".to_string())
}

// ── Cognitive Runtime Commands ──────────────────────────────────────────────

fn assign_agent_goal(
    state: &AppState,
    agent_id: String,
    goal_description: String,
    priority: u8,
) -> Result<String, String> {
    state.check_rate(nexus_kernel::rate_limit::RateCategory::AgentExecute)?;
    state.validate_input(&goal_description)?;
    let effective_goal_description = goal_with_manifest_context(
        &agent_id,
        &goal_description,
        find_manifest_description(state, &agent_id).as_deref(),
    );
    let goal = nexus_kernel::cognitive::AgentGoal::new(effective_goal_description, priority);
    let goal_id = goal.id.clone();
    state
        .cognitive_runtime
        .assign_goal(&agent_id, goal)
        .map_err(|e| e.to_string())?;
    state.log_event(
        Uuid::parse_str(&agent_id).unwrap_or_default(),
        EventType::UserAction,
        json!({"action": "assign_agent_goal", "agent_id": agent_id, "goal_id": goal_id}),
    );
    Ok(goal_id)
}

fn persist_task_start(state: &AppState, agent_id: &str, goal_id: &str) {
    let goal = state
        .cognitive_runtime
        .get_agent_status(agent_id)
        .and_then(|status| status.active_goal.map(|goal| goal.description))
        .unwrap_or_else(|| "unknown goal".to_string());
    let fuel_budget = {
        let supervisor = state.supervisor.lock().unwrap_or_else(|p| p.into_inner());
        agent_id.parse::<Uuid>().ok().and_then(|uuid| {
            supervisor
                .get_agent(uuid)
                .map(|handle| handle.remaining_fuel as f64)
        })
    };
    let task = nexus_persistence::TaskRow {
        id: goal_id.to_string(),
        agent_id: agent_id.to_string(),
        goal,
        status: "running".to_string(),
        steps_json: "[]".to_string(),
        result_json: None,
        fuel_consumed: 0.0,
        fuel_budget,
        estimated_time_secs: None,
        actual_time_secs: None,
        quality_score: None,
        started_at: chrono::Utc::now().to_rfc3339(),
        completed_at: None,
        success: false,
    };
    if let Err(error) = state.db.save_task(&task) {
        eprintln!("persistence: save_task start failed: {error}");
    }
}

fn persist_task_completion(
    state: &AppState,
    agent_id: &str,
    goal_id: &str,
    status: &str,
    result_summary: &str,
    success: bool,
    fallback_fuel_consumed: f64,
) {
    let fuel_consumed = state
        .db
        .load_tasks_by_agent(agent_id, 100)
        .ok()
        .and_then(|tasks| {
            let initial_budget = tasks
                .into_iter()
                .find(|task| task.id == goal_id)
                .and_then(|task| task.fuel_budget)?;
            let supervisor = state.supervisor.lock().unwrap_or_else(|p| p.into_inner());
            let remaining = agent_id
                .parse::<Uuid>()
                .ok()
                .and_then(|uuid| {
                    supervisor
                        .get_agent(uuid)
                        .map(|handle| handle.remaining_fuel as f64)
                })
                .unwrap_or(initial_budget);
            Some((initial_budget - remaining).max(0.0))
        })
        .unwrap_or(fallback_fuel_consumed);
    let result_json = json!({ "summary": result_summary }).to_string();
    if let Err(error) =
        state
            .db
            .update_task_status(goal_id, status, Some(&result_json), fuel_consumed, success)
    {
        eprintln!("persistence: update_task_status failed: {error}");
    }
    state.log_event(
        Uuid::parse_str(agent_id).unwrap_or_default(),
        EventType::StateChange,
        json!({
            "action": "agent_goal_completed",
            "goal_id": goal_id,
            "status": status,
            "success": success,
            "result_summary": result_summary,
        }),
    );
}

#[derive(Debug, Clone, Serialize, Deserialize)]
struct AgentCheckpointSnapshot {
    status: String,
    fuel_remaining: u64,
    memories: Vec<nexus_persistence::MemoryRow>,
}

fn capture_agent_snapshot(state: &AppState, agent_id: &str) -> Option<AgentCheckpointSnapshot> {
    let status = {
        let supervisor = state.supervisor.lock().unwrap_or_else(|p| p.into_inner());
        let uuid = Uuid::parse_str(agent_id).ok()?;
        let handle = supervisor.get_agent(uuid)?;
        handle.state.to_string()
    };
    let fuel_remaining = {
        let supervisor = state.supervisor.lock().unwrap_or_else(|p| p.into_inner());
        let uuid = Uuid::parse_str(agent_id).ok()?;
        supervisor
            .get_agent(uuid)
            .map(|handle| handle.remaining_fuel)?
    };
    let memories = state.db.load_memories(agent_id, None, 250).ok()?;
    Some(AgentCheckpointSnapshot {
        status,
        fuel_remaining,
        memories,
    })
}

fn snapshot_state_hash(snapshot: &AgentCheckpointSnapshot) -> String {
    let serialized = serde_json::to_vec(snapshot).unwrap_or_default();
    format!("{:x}", sha2::Sha256::digest(serialized))
}

fn save_checkpoint_to_db(state: &AppState, checkpoint: &nexus_kernel::time_machine::Checkpoint) {
    let serialized = match serde_json::to_string(checkpoint) {
        Ok(serialized) => serialized,
        Err(error) => {
            eprintln!(
                "time-machine: failed to serialize checkpoint {}: {error}",
                checkpoint.id
            );
            return;
        }
    };
    let row = CheckpointRow {
        id: checkpoint.id.clone(),
        agent_id: checkpoint.agent_id.clone().unwrap_or_default(),
        state_json: serialized,
        description: Some(checkpoint.label.clone()),
        created_at: chrono::Utc
            .timestamp_millis_opt(checkpoint.timestamp as i64)
            .single()
            .unwrap_or_else(chrono::Utc::now)
            .to_rfc3339(),
    };
    if let Err(error) = state.db.save_checkpoint(&row) {
        eprintln!(
            "time-machine: failed to persist checkpoint {}: {error}",
            checkpoint.id
        );
    }
}

fn commit_time_machine_checkpoint(
    state: &AppState,
    checkpoint: nexus_kernel::time_machine::Checkpoint,
) -> Result<String, String> {
    let checkpoint_id = {
        let mut supervisor = state.supervisor.lock().unwrap_or_else(|p| p.into_inner());
        let (id, _) = supervisor
            .time_machine_mut()
            .commit_checkpoint(checkpoint.clone())
            .map_err(|e| e.to_string())?;
        id
    };
    save_checkpoint_to_db(state, &checkpoint);
    Ok(checkpoint_id)
}

fn record_agent_execution_checkpoint(
    state: &AppState,
    agent_id: &str,
    label: &str,
    before: Option<&AgentCheckpointSnapshot>,
    after: Option<&AgentCheckpointSnapshot>,
    action: &str,
) {
    let Some(after_snapshot) = after.cloned() else {
        return;
    };
    let before_snapshot = before.cloned().unwrap_or_else(|| after_snapshot.clone());

    let before_memories =
        serde_json::to_value(&before_snapshot.memories).unwrap_or_else(|_| json!([]));
    let after_memories =
        serde_json::to_value(&after_snapshot.memories).unwrap_or_else(|_| json!([]));
    let mut builder = {
        let supervisor = state.supervisor.lock().unwrap_or_else(|p| p.into_inner());
        supervisor
            .time_machine()
            .begin_checkpoint(label, Some(agent_id.to_string()))
    };
    builder.record_agent_state(
        agent_id,
        "status",
        json!(before_snapshot.status),
        json!(after_snapshot.status),
    );
    builder.record_agent_state(
        agent_id,
        "fuel_remaining",
        json!(before_snapshot.fuel_remaining),
        json!(after_snapshot.fuel_remaining),
    );
    builder.record_agent_state(agent_id, "memories", before_memories, after_memories);
    builder.record_config_change(
        "state_hash",
        json!(snapshot_state_hash(&before_snapshot)),
        json!(snapshot_state_hash(&after_snapshot)),
    );
    builder.record_config_change("action", json!(label), json!(action));
    let checkpoint = builder.build();
    let _ = commit_time_machine_checkpoint(state, checkpoint);
}

fn parse_agent_state(value: &str) -> Option<AgentState> {
    match value {
        "Created" => Some(AgentState::Created),
        "Starting" => Some(AgentState::Starting),
        "Running" => Some(AgentState::Running),
        "Paused" => Some(AgentState::Paused),
        "Stopping" => Some(AgentState::Stopping),
        "Stopped" => Some(AgentState::Stopped),
        "Destroyed" => Some(AgentState::Destroyed),
        _ => None,
    }
}

fn restore_agent_memories(state: &AppState, agent_id: &str, value: &serde_json::Value) {
    let Ok(memories) = serde_json::from_value::<Vec<nexus_persistence::MemoryRow>>(value.clone())
    else {
        return;
    };
    let _ = state.db.delete_memories_by_agent(agent_id);
    for memory in memories {
        let _ = state.db.save_memory(
            &memory.agent_id,
            &memory.memory_type,
            &memory.key,
            &memory.value_json,
        );
    }
}

fn apply_non_file_undo_actions(
    state: &AppState,
    actions: &[nexus_kernel::time_machine::UndoAction],
) {
    for action in actions {
        match action {
            nexus_kernel::time_machine::UndoAction::RestoreAgentState {
                agent_id,
                field,
                value,
            } => {
                if let Ok(agent_uuid) = Uuid::parse_str(agent_id) {
                    let mut supervisor = state.supervisor.lock().unwrap_or_else(|p| p.into_inner());
                    if let Some(handle) = supervisor.get_agent_mut(agent_uuid) {
                        match field.as_str() {
                            "status" => {
                                if let Some(status) = value.as_str().and_then(parse_agent_state) {
                                    handle.state = status;
                                }
                            }
                            "fuel_remaining" => {
                                if let Some(fuel) = value.as_u64() {
                                    handle.remaining_fuel = fuel;
                                }
                            }
                            _ => {}
                        }
                    }
                }
                if field == "memories" {
                    restore_agent_memories(state, agent_id, value);
                }
            }
            nexus_kernel::time_machine::UndoAction::RestoreConfig { key, value } => {
                if key == "state_hash" || key == "action" {
                    continue;
                }
                let Ok(mut config) = load_config() else {
                    continue;
                };
                if key == "governance.enable_warden_review" {
                    if let Some(enabled) = value.as_bool() {
                        config.governance.enable_warden_review = enabled;
                        let _ = save_nexus_config(&config);
                    }
                }
            }
            _ => {}
        }
    }
}

fn task_timing_for_goal(state: &AppState, agent_id: &str, goal_id: &str) -> Option<(f64, f64)> {
    let tasks = state.db.load_tasks_by_agent(agent_id, 200).ok()?;
    let task = tasks.into_iter().find(|task| task.id == goal_id)?;
    let started = chrono::DateTime::parse_from_rfc3339(&task.started_at).ok()?;
    let completed = task
        .completed_at
        .as_deref()
        .and_then(|value| chrono::DateTime::parse_from_rfc3339(value).ok())
        .unwrap_or_else(|| chrono::Utc::now().into());
    Some((
        ((completed - started).num_milliseconds().max(0) as f64) / 1000.0,
        task.fuel_budget.unwrap_or(0.0),
    ))
}

fn recent_task_outcomes(state: &AppState, agent_id: &str, limit: usize) -> Vec<(bool, f64, f64)> {
    state
        .db
        .load_tasks_by_agent(agent_id, limit)
        .unwrap_or_default()
        .into_iter()
        .filter_map(|task| {
            let started = chrono::DateTime::parse_from_rfc3339(&task.started_at).ok()?;
            let completed = task
                .completed_at
                .as_deref()
                .and_then(|value| chrono::DateTime::parse_from_rfc3339(value).ok())
                .unwrap_or_else(|| chrono::Utc::now().into());
            Some((
                task.success,
                task.fuel_consumed,
                ((completed - started).num_milliseconds().max(0) as f64) / 1000.0,
            ))
        })
        .collect()
}

fn run_post_goal_evolution(
    bridge: &BackendEventBridge,
    state: &AppState,
    agent_id: &str,
    goal_id: &str,
    success: bool,
    fallback_fuel_consumed: f64,
) {
    let (autonomy_level, agent_name) = {
        let supervisor = state.supervisor.lock().unwrap_or_else(|p| p.into_inner());
        let Some(handle) = Uuid::parse_str(agent_id)
            .ok()
            .and_then(|uuid| supervisor.get_agent(uuid))
        else {
            return;
        };
        (handle.autonomy_level, handle.manifest.name.clone())
    };

    if autonomy_level < 4 {
        return;
    }

    let mem_store = DbMemoryStore {
        db: state.db.clone(),
    };
    let memory_mgr = nexus_kernel::cognitive::AgentMemoryManager::new(Box::new(mem_store));
    let (duration_secs, fuel_budget) =
        task_timing_for_goal(state, agent_id, goal_id).unwrap_or((0.0, fallback_fuel_consumed));
    let fuel_consumed = state
        .db
        .load_tasks_by_agent(agent_id, 200)
        .ok()
        .and_then(|tasks| tasks.into_iter().find(|task| task.id == goal_id))
        .map(|task| task.fuel_consumed)
        .unwrap_or(fallback_fuel_consumed);
    let goal_type = state
        .db
        .load_tasks_by_agent(agent_id, 200)
        .ok()
        .and_then(|tasks| tasks.into_iter().find(|task| task.id == goal_id))
        .map(|task| task.goal)
        .unwrap_or_else(|| "scheduled_goal".to_string())
        .to_lowercase();
    let strategy_hash = nexus_kernel::cognitive::hash_strategy(&goal_type);

    let _ = state.evolution_tracker.record_task_result(
        agent_id,
        goal_id,
        &strategy_hash,
        &goal_type,
        success,
        fuel_consumed,
        duration_secs,
        fuel_budget,
        60.0,
        &memory_mgr,
    );

    let completed_count = state
        .db
        .load_tasks_by_agent(agent_id, 500)
        .unwrap_or_default()
        .into_iter()
        .filter(|task| task.completed_at.is_some())
        .count();

    if completed_count > 0 && completed_count % 5 == 0 {
        if let Ok(Some(best_strategy)) = state
            .evolution_tracker
            .select_best_strategy(agent_id, &goal_type)
        {
            let _ = memory_mgr.store_procedural(
                agent_id,
                &format!("planner_strategy_injection:{best_strategy}"),
                1.0,
            );
            if let Ok(strategies) = state.evolution_tracker.get_agent_strategies(agent_id) {
                if let Some(strategy) = strategies
                    .into_iter()
                    .find(|entry| entry.strategy_hash == best_strategy)
                {
                    let score = strategy.composite_score;
                    let generation = (completed_count / 5) as u64;
                    state.log_event(
                        Uuid::parse_str(agent_id).unwrap_or_default(),
                        EventType::StateChange,
                        json!({
                            "action": "agent_evolved_strategy",
                            "message": format!("Agent {} evolved strategy. New composite score: {:.3}", agent_name, score),
                            "new_score": score,
                            "generation": generation,
                            "strategy_hash": best_strategy,
                        }),
                    );
                    bridge.emit(
                        "agent-evolved",
                        json!({
                            "agent_id": agent_id,
                            "new_score": score,
                            "generation": generation,
                            "strategy_hash": best_strategy,
                        }),
                    );
                }
            }
        }
    }

    if completed_count > 0 && completed_count % 10 == 0 {
        let outcomes = recent_task_outcomes(state, agent_id, 10);
        let current_prompt = format!(
            "Plan safe, governed work for agent {} while respecting its capabilities and audit trail.",
            agent_name
        );
        let llm = GatewayPlannerLlm;
        let _ = state.evolution_tracker.optimize_planning_prompt(
            agent_id,
            &current_prompt,
            &outcomes,
            &llm,
            &memory_mgr,
        );
    }
}

/// Bridges the configured LLM provider to the cognitive planner's `PlannerLlm` trait.
struct GatewayPlannerLlm;

/// Bridges the cognitive loop's LlmQuery actions to the configured LLM provider.
///
/// When an agent's plan includes a step like "analyze these file contents" or
/// "summarize this data", the RegistryExecutor delegates to this handler which
/// routes through the same LLM provider infrastructure as the planner.
struct BridgeLlmQueryHandler;

impl nexus_kernel::cognitive::LlmQueryHandler for BridgeLlmQueryHandler {
    fn query(&self, prompt: &str) -> Result<String, String> {
        nexus_kernel::cognitive::PlannerLlm::plan_query(&GatewayPlannerLlm, prompt)
            .map_err(|e| e.to_string())
    }
}

impl nexus_kernel::cognitive::PlannerLlm for GatewayPlannerLlm {
    fn plan_query(&self, prompt: &str) -> Result<String, nexus_kernel::errors::AgentError> {
        // If a Flash Inference provider is loaded, use it. The agent WAITS for Flash
        // (blocking lock) rather than falling back to Ollama, because Ollama may be dead
        // and Flash is the primary local provider. llama.cpp is single-threaded, so queries
        // are serialized — the agent simply waits its turn behind the UI.
        let flash = ACTIVE_FLASH_PROVIDER.with(|slot| slot.borrow().clone());
        if let Some(flash_provider) = flash {
            let prompt_chars = prompt.len();
            eprintln!("[planner] using Flash Inference, prompt len={prompt_chars} chars");

            // Run Flash query in a dedicated OS thread. This isolates the main
            // app from llama.cpp crashes (segfaults in FFI). If the thread dies,
            // we get an error instead of the whole app crashing.
            let prompt_owned = prompt.to_string();
            let handle = std::thread::spawn(move || {
                // Cap max_tokens to 1024 for planner — a JSON plan is 200-500 tokens.
                flash_provider.query(&prompt_owned, 1024, "flash")
            });

            match handle.join() {
                Ok(Ok(response)) => {
                    eprintln!(
                        "[planner] Flash Inference query complete ({} chars)",
                        response.output_text.len()
                    );
                    return Ok(strip_think_tags(&response.output_text));
                }
                Ok(Err(e)) => {
                    eprintln!("[planner] Flash Inference error: {e}");
                    return Err(e);
                }
                Err(_) => {
                    eprintln!(
                        "[planner] Flash Inference thread crashed (segfault or panic in llama.cpp)"
                    );
                    return Err(nexus_kernel::errors::AgentError::SupervisorError(
                        "Flash Inference crashed during query — the model may be corrupted or out of memory. \
                         Try reloading the model from the Flash Inference page."
                            .to_string(),
                    ));
                }
            }
        }

        eprintln!(
            "[CRASH-TRACE-30] Flash not available/busy, loading config for standard provider"
        );
        let config = nexus_kernel::config::load_config().unwrap_or_default();
        let prov_config = build_provider_config(&config);
        let route_model = ACTIVE_AGENT_LLM_ROUTE
            .with(|slot| slot.borrow().as_ref().map(|route| route.model.clone()));
        eprintln!(
            "[CRASH-TRACE-31] route_model={:?}",
            route_model.as_deref().unwrap_or("none")
        );
        let (provider, model) = if let Some(route_model) = route_model {
            // Skip flash routes — already handled by ACTIVE_FLASH_PROVIDER above.
            // If we reach here, Flash was requested but couldn't be resolved.
            if route_model.starts_with("flash:")
                || route_model.starts_with("flash/")
                || route_model == "flash"
            {
                // Flash provider wasn't available — return clear error instead of
                // silently falling back to Ollama (which causes confusing 404 errors).
                return Err(nexus_kernel::errors::AgentError::SupervisorError(
                    "Flash Inference is selected but no model is loaded. \
                     Go to the Agents page and click 'Load Model' to start a Flash session."
                        .to_string(),
                ));
            } else {
                provider_from_prefixed_model(&route_model, &prov_config).unwrap_or_else(|_| {
                    (
                        select_provider(&prov_config).unwrap_or_else(|_| {
                            Box::new(OllamaProvider::from_env()) as Box<dyn LlmProvider>
                        }),
                        route_model,
                    )
                })
            }
        } else {
            let provider = select_provider(&prov_config)?;
            let model = if config.llm.default_model.trim().is_empty() {
                if provider.name() == "ollama" {
                    let ollama = OllamaProvider::from_env();
                    ollama
                        .list_models()
                        .ok()
                        .and_then(|models| models.into_iter().next().map(|m| m.name))
                        .unwrap_or_else(|| "llama3.2".to_string())
                } else {
                    "mock-1".to_string()
                }
            } else {
                config.llm.default_model.clone()
            };
            (provider, model)
        };
        eprintln!(
            "[CRASH-TRACE-32] about to call provider.query() on provider={}",
            provider.name()
        );
        // Wrap the LLM query in catch_unwind as a last resort — if the provider
        // crashes (e.g., llama.cpp segfault caught by signal handler, or Ollama timeout),
        // we return an error instead of killing the app.
        let query_result = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
            provider.query(prompt, 4096, &model)
        }));
        eprintln!("[CRASH-TRACE-33] provider.query() returned (survived)");
        match query_result {
            Ok(Ok(response)) => Ok(strip_think_tags(&response.output_text)),
            Ok(Err(e)) => Err(e),
            Err(_panic) => Err(nexus_kernel::errors::AgentError::SupervisorError(
                "LLM provider panicked during query — model may be corrupted or out of memory"
                    .to_string(),
            )),
        }
    }
}

/// Strip `<think>...</think>` reasoning blocks from LLM output.
/// Qwen3 and similar models emit these blocks for chain-of-thought reasoning;
/// they must be removed before the output reaches the JSON parser or the user.
fn strip_think_tags(input: &str) -> String {
    let mut result = input.to_string();
    while let Some(start) = result.find("<think>") {
        if let Some(end) = result[start..].find("</think>") {
            result = format!("{}{}", &result[..start], &result[start + end + 8..]);
        } else {
            // Unclosed <think> — remove to end
            result.truncate(start);
            break;
        }
    }
    result
}

impl nexus_kernel::cognitive::EvolutionLlm for GatewayPlannerLlm {
    fn optimize_prompt(&self, prompt: &str) -> Result<String, String> {
        nexus_kernel::cognitive::PlannerLlm::plan_query(self, prompt)
            .map_err(|error| error.to_string())
    }
}

impl nexus_kernel::genome::AutoEvolveLlm for GatewayPlannerLlm {
    fn score_response(&self, user_message: &str, agent_response: &str) -> Result<f64, String> {
        let prompt = format!(
            "Rate this AI agent response on a scale of 1-10.\n\
             User asked: {user_message}\n\
             Agent responded: {agent_response}\n\n\
             Score based on: relevance, accuracy, helpfulness, conciseness.\n\
             Return ONLY a number 1-10, nothing else."
        );
        let text = nexus_kernel::cognitive::PlannerLlm::plan_query(self, &prompt)
            .map_err(|e| e.to_string())?;
        // Parse the first number found in the response
        let score = text
            .trim()
            .split(|c: char| !c.is_ascii_digit() && c != '.')
            .find(|s| !s.is_empty())
            .and_then(|s| s.parse::<f64>().ok())
            .unwrap_or(7.0);
        Ok(score.clamp(1.0, 10.0))
    }

    fn mutate_prompt(
        &self,
        current_prompt: &str,
        weak_responses: &[(String, String, f64)],
    ) -> Result<String, String> {
        let mut weak_desc = String::new();
        for (i, (user_msg, agent_resp, score)) in weak_responses.iter().enumerate() {
            weak_desc.push_str(&format!(
                "Task {}: User asked: {user_msg}\n  Agent said: {agent_resp}\n  Score: {score}/10\n\n",
                i + 1
            ));
        }
        let prompt = format!(
            "Here is an AI agent's system prompt:\n{current_prompt}\n\n\
             It performed poorly on these tasks:\n{weak_desc}\n\
             Analyze WHY the responses were weak and rewrite the system prompt \
             to address these specific weaknesses. Keep the core personality \
             and capabilities, but add targeted instructions to improve.\n\n\
             Return ONLY the improved system prompt."
        );
        nexus_kernel::cognitive::PlannerLlm::plan_query(self, &prompt).map_err(|e| e.to_string())
    }

    fn generate_with_prompt(
        &self,
        system_prompt: &str,
        user_message: &str,
    ) -> Result<String, String> {
        let prompt =
            format!("[System prompt: {system_prompt}]\n\nUser: {user_message}\n\nAssistant:");
        nexus_kernel::cognitive::PlannerLlm::plan_query(self, &prompt).map_err(|e| e.to_string())
    }
}

#[cfg(not(test))]
struct SimulationPlannerLlm;

#[cfg(not(test))]
impl nexus_kernel::cognitive::PlannerLlm for SimulationPlannerLlm {
    fn plan_query(&self, prompt: &str) -> Result<String, nexus_kernel::errors::AgentError> {
        let gateway = GatewayPlannerLlm;
        match gateway.plan_query(prompt) {
            Ok(response) if simulation_response_is_usable(prompt, &response) => Ok(response),
            Ok(_) | Err(_) => Ok(simulation_mock_response(prompt)),
        }
    }
}

