    #[test]
    fn test_approve_consent_request_wakes_blocked_wait() {
        let state = AppState::new_in_memory();
        enqueue_test_consent(&state, "c-approve-wake", "a1", "fs.write", "Tier1");
        let notify = state.register_blocked_consent_wait("a1", "c-approve-wake");
        let runtime = tokio::runtime::Builder::new_current_thread()
            .enable_time()
            .build()
            .unwrap_or_else(|e| {
                eprintln!("operation failed: {e}");
                std::process::exit(1)
            });

        runtime.block_on(async {
            let waiter = tokio::spawn({
                let notify = notify.clone();
                async move {
                    notify.notified().await;
                }
            });

            approve_consent_request(&state, "c-approve-wake".into(), "admin".into())
                .unwrap_or_else(|e| {
                    eprintln!("operation failed: {e}");
                    std::process::exit(1)
                });

            tokio::time::timeout(std::time::Duration::from_millis(100), waiter)
                .await
                .unwrap_or_else(|e| {
                    eprintln!("operation failed: {e}");
                    std::process::exit(1)
                })
                .unwrap_or_else(|e| {
                    eprintln!("operation failed: {e}");
                    std::process::exit(1)
                });
        });
    }

